import React, { useState, useEffect, useRef } from 'react';
import { executeCode } from '../services/compilerService';
import { collabService } from '../services/collaborationService';
import { CollabMessage, Peer } from '../types';

const LANGUAGES = {
  javascript: { name: 'JS', snippet: `console.log("Hello World");` },
  python: { name: 'Python', snippet: `print("Hello World")` },
  typescript: { name: 'TS', snippet: `console.log("Hello TS");` },
  java: { name: 'Java', snippet: `public class Main {\n  public static void main(String[] args) {\n    System.out.println("Hello");\n  }\n}` },
  cpp: { name: 'C++', snippet: `#include <iostream>\nint main() {\n  std::cout << "Hello";\n  return 0;\n}` }
};

type LanguageKey = keyof typeof LANGUAGES;

interface CodeEditorProps {
    onReviewRequest: (code: string, language: string) => Promise<void>;
}

export const CodeEditor: React.FC<CodeEditorProps> = ({ onReviewRequest }) => {
  const [language, setLanguage] = useState<LanguageKey>('javascript');
  const [code, setCode] = useState<string>(LANGUAGES.javascript.snippet);
  const [output, setOutput] = useState<string[]>([]);
  const [isRunning, setIsRunning] = useState(false);
  const [activeView, setActiveView] = useState<'edit' | 'console'>('edit');
  const [peers, setPeers] = useState<Peer[]>([]);

  // Collaboration Setup
  useEffect(() => {
    const handleCollabMessage = (msg: CollabMessage) => {
        if (msg.type === 'CODE_UPDATE') {
            // Only update if content is different to minimize cursor disruption
            setCode(prev => {
                if (prev !== msg.payload.code) return msg.payload.code;
                return prev;
            });
        } else if (msg.type === 'LANGUAGE_UPDATE') {
            setLanguage(msg.payload.language);
        }
    };

    const handlePeerUpdate = (activePeers: Peer[]) => {
        setPeers(activePeers);
    };

    collabService.subscribe(handleCollabMessage);
    collabService.subscribeToPeers(handlePeerUpdate);

    return () => {
        collabService.unsubscribe(handleCollabMessage);
        collabService.unsubscribe(handlePeerUpdate);
    };
  }, []);

  const handleCodeChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
      const newCode = e.target.value;
      setCode(newCode);
      collabService.broadcast('CODE_UPDATE', { code: newCode });
  };

  const handleLanguageChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
      const newLang = e.target.value as LanguageKey;
      setLanguage(newLang);

      const newCode = LANGUAGES[newLang].snippet;
      setCode(newCode);

      collabService.broadcast('LANGUAGE_UPDATE', { language: newLang });
      collabService.broadcast('CODE_UPDATE', { code: newCode });
  };

  const runCode = async () => {
    setIsRunning(true);
    setActiveView('console');
    setOutput(['Running...']);

    // Simulate slight delay for "app" feel
    setTimeout(async () => {
        try {
            if (language === 'javascript') {
                const logs: string[] = [];
                const originalLog = console.log;
                console.log = (...args) => logs.push(args.join(' '));
                try { new Function(code)(); } catch (e: any) { logs.push(e.toString()); }
                console.log = originalLog;
                setOutput(logs.length ? logs : ['No output']);
            } else {
                const res = await executeCode(language, code);
                setOutput(res.error ? [res.error] : res.output.split('\n'));
            }
        } catch (e: any) {
            setOutput([`Error: ${e.message}`]);
        } finally {
            setIsRunning(false);
        }
    }, 500);
  };

  return (
    <div className="flex flex-col h-full bg-[#1e1e1e]">
      {/* Editor Toolbar */}
      <div className="flex items-center justify-between px-4 py-2 bg-[#252526] border-b border-[#333]">
         <div className="flex items-center gap-3">
             <select 
                value={language}
                onChange={handleLanguageChange}
                className="bg-[#333] text-white text-xs rounded px-2 py-1.5 outline-none border-none font-medium"
             >
                {Object.entries(LANGUAGES).map(([k, v]) => <option key={k} value={k}>{v.name}</option>)}
             </select>

             {/* Peer Avatars */}
             <div className="flex items-center -space-x-2">
                {peers.map((peer) => (
                    <div 
                        key={peer.id} 
                        className="w-6 h-6 rounded-full border border-[#252526] flex items-center justify-center text-[10px] font-bold text-white shadow-sm"
                        style={{ backgroundColor: peer.color }}
                        title={peer.username}
                    >
                        {peer.username.slice(0, 1)}
                    </div>
                ))}
                {peers.length > 0 && (
                     <div className="w-6 h-6 rounded-full bg-[#333] border border-[#252526] flex items-center justify-center text-[9px] text-gray-400">
                        +{peers.length}
                     </div>
                )}
             </div>
         </div>

         <div className="flex gap-2">
             <button 
                onClick={() => onReviewRequest(code, language)}
                className="p-2 text-purple-400 hover:bg-purple-900/20 rounded-full"
                title="AI Review"
             >
                <span className="material-symbols-rounded text-[20px]">smart_toy</span>
             </button>
             <button 
                onClick={runCode}
                disabled={isRunning}
                className="p-2 text-green-400 hover:bg-green-900/20 rounded-full"
                title="Run Code"
             >
                <span className={`material-symbols-rounded text-[20px] ${isRunning ? 'animate-spin' : ''}`}>
                    {isRunning ? 'sync' : 'play_arrow'}
                </span>
             </button>
         </div>
      </div>

      {/* Content Area */}
      <div className="flex-1 relative">
         <textarea
            value={code}
            onChange={handleCodeChange}
            className={`w-full h-full bg-[#1e1e1e] text-[#d4d4d4] p-4 font-mono text-sm resize-none outline-none leading-relaxed ${activeView === 'console' ? 'hidden' : 'block'}`}
            spellCheck={false}
         />

         {/* Console View Overlay */}
         <div className={`absolute inset-0 bg-[#0d0d0d] p-4 font-mono text-sm overflow-auto ${activeView === 'console' ? 'block' : 'hidden'}`}>
             <div className="flex justify-between items-center mb-2 border-b border-gray-800 pb-2">
                 <span className="text-gray-500 text-xs uppercase tracking-wider">Console Output</span>
                 <button onClick={() => setActiveView('edit')} className="text-blue-400 text-xs">CLOSE</button>
             </div>
             {output.map((line, i) => (
                 <div key={i} className="text-gray-300 mb-1 break-all">{line}</div>
             ))}
         </div>
      </div>

      {/* View Toggle (Bottom of Editor) */}
      <div className="flex border-t border-[#333]">
          <button 
            onClick={() => setActiveView('edit')}
            className={`flex-1 py-3 text-xs font-medium uppercase tracking-wider ${activeView === 'edit' ? 'text-blue-400 bg-[#2d2d2d]' : 'text-gray-500'}`}
          >
            Editor
          </button>
          <button 
            onClick={() => setActiveView('console')}
            className={`flex-1 py-3 text-xs font-medium uppercase tracking-wider ${activeView === 'console' ? 'text-blue-400 bg-[#2d2d2d]' : 'text-gray-500'}`}
          >
            Console {output.length > 0 && '•'}
          </button>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { v4 as uuidv4 } from 'uuid';
import * as pdfjsLib from 'pdfjs-dist';
import { 
  generateInterviewQuestion, 
  generateImage,
  connectToLiveSession,
  reviewCodeWithAI,
  ResumeData
} from './services/geminiService';
import { decodeAudioData, downsampleBuffer } from './utils/audioUtils';
import { TerminalMessage } from './components/TerminalMessage';
import { CodeEditor } from './components/CodeEditor';
import { Message, Sender, InterviewMode, Persona, Attachment } from './types';

const App: React.FC = () => {
  // Navigation State
  const [activeTab, setActiveTab] = useState<'chat' | 'code'>('chat');

  // App Logic State
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [mode, setMode] = useState<InterviewMode>(InterviewMode.TEXT);
  const [persona, setPersona] = useState<Persona>(Persona.INTERVIEWER);
  const [isLiveConnected, setIsLiveConnected] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [tokenMissing, setTokenMissing] = useState(false);

  // Data State
  const [resumeData, setResumeData] = useState<ResumeData | undefined>(undefined);
  const [pendingAttachment, setPendingAttachment] = useState<Attachment | null>(null);

  // Refs
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const synthRef = useRef<SpeechSynthesis>(window.speechSynthesis);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Audio Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const sourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const liveSessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef<number>(0);
  const audioSourcesRef = useRef<AudioBufferSourceNode[]>([]);
  const currentTurnTextRef = useRef<string>("");

  // Init
  useEffect(() => {
    // PDF Worker
    const pdfjs = pdfjsLib as any;
    const workerOptions = pdfjs.GlobalWorkerOptions || pdfjs.default?.GlobalWorkerOptions || (window as any).pdfjsLib?.GlobalWorkerOptions;
    if (workerOptions) workerOptions.workerSrc = "https://unpkg.com/pdfjs-dist@3.11.174/build/pdf.worker.min.js";

    const key = process.env.API_KEY;
    if (!key || key.trim() === '') {
        setTokenMissing(true);
        addMessage(Sender.SYSTEM, "Configuration Error: API_KEY is missing.");
    } else {
        setTimeout(() => addMessage(Sender.AI, "Welcome. I am your Nexus AI Assistant. Ready for your technical assessment."), 500);
    }

    return () => { if (audioContextRef.current) audioContextRef.current.close(); };
  }, []);

  // Auto-scroll
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isLoading, pendingAttachment, activeTab]);

  const addMessage = (sender: Sender, text: string, grounding?: any[], isThinking = false, imageData?: string, attachment?: Attachment) => {
    const id = uuidv4();
    setMessages(prev => [...prev, {
      id,
      sender,
      text,
      timestamp: Date.now(),
      grounding,
      isThinking,
      imageData,
      attachment
    }]);
    return id;
  };

  const updateLastMessage = (text: string, sender: Sender) => {
      setMessages(prev => {
          const last = prev[prev.length - 1];
          if (last && last.sender === sender) {
              return [...prev.slice(0, -1), { ...last, text: text }];
          } else {
              return [...prev, { id: uuidv4(), sender, text, timestamp: Date.now() }];
          }
      });
  };

  const playTTS = (text: string) => {
    if (!synthRef.current || mode === InterviewMode.VOICE) return;
    synthRef.current.cancel();
    const utterance = new SpeechSynthesisUtterance(text.replace(/[*#`_]/g, ''));
    const voices = synthRef.current.getVoices();
    const preferred = voices.find(v => v.name.includes('Google US English') || v.lang === 'en-US');
    if (preferred) utterance.voice = preferred;
    synthRef.current.speak(utterance);
  };

  // --- Voice Logic ---
  const stopAudioPlayback = () => {
      // Stop Web Audio API sources (Live API)
      audioSourcesRef.current.forEach(source => { try { source.stop(); } catch (e) {} });
      audioSourcesRef.current = [];

      // Stop Browser TTS
      if (synthRef.current) {
          synthRef.current.cancel();
      }
  };

  const handleTextSubmit = async (e?: React.FormEvent, overrideText?: string) => {
    e?.preventDefault();
    const textToSend = overrideText || inputValue;
    if (!textToSend.trim() && !pendingAttachment) return;

    const attachment = pendingAttachment;
    setPendingAttachment(null);
    if (!overrideText) setInputValue('');

    addMessage(Sender.USER, textToSend, undefined, undefined, undefined, attachment || undefined);
    if (tokenMissing) return;

    if (textToSend.toLowerCase() === '/code') {
        setActiveTab('code');
        addMessage(Sender.SYSTEM, "Switched to Workspace");
        return;
    }

    setIsLoading(true);

    const history = messages.slice(-6).filter(m => !m.imageData).map(m => `${m.sender}: ${m.text}`).join('\n');
    let promptToSend = textToSend;
    let imageContext: { mimeType: string; data: string } | undefined;

    if (attachment) {
      if (attachment.type === 'image') {
        imageContext = { mimeType: attachment.mimeType, data: attachment.data };
        promptToSend += `\n[User attached an image]`;
      } else {
        promptToSend += `\n\n[FILE: ${attachment.fileName}]\n${attachment.data}`;
      }
    }

    try {
        const response = await generateInterviewQuestion(
            history + `\nUSER: ${promptToSend}`,
            persona,
            false,
            resumeData,
            imageContext
        );

        setIsLoading(false);
        const msgId = addMessage(Sender.AI, response.text, response.grounding);
        playTTS(response.text);

        if (response.isCodingChallenge) {
          setActiveTab('code');
          addMessage(Sender.SYSTEM, "Coding Challenge Started - Workspace Active");
        }

        if (response.imagePrompt) {
            generateImage(response.imagePrompt)
                .then(url => setMessages(prev => prev.map(m => m.id === msgId ? { ...m, imageData: url } : m)))
                .catch(console.error);
        }
    } catch (e: any) {
        setIsLoading(false);
        addMessage(Sender.SYSTEM, `Error: ${e.message}`);
    }
  };

  const handleCodeReviewRequest = async (code: string, language: string) => {
    setActiveTab('chat');
    addMessage(Sender.USER, `Submitted ${language} solution for review.`);
    setIsLoading(true);
    addMessage(Sender.SYSTEM, "Analyzing Solution...");
    try {
        const feedback = await reviewCodeWithAI(language, code);
        setIsLoading(false);
        addMessage(Sender.AI, feedback);
        playTTS(feedback);
    } catch (e: any) {
        setIsLoading(false);
        addMessage(Sender.SYSTEM, `Review Error: ${e.message}`);
    }
  };

  const toggleVoiceMode = async () => {
    if (mode === InterviewMode.VOICE) {
        setMode(InterviewMode.TEXT);
        setIsLiveConnected(false);
        if (liveSessionRef.current) { liveSessionRef.current.disconnect(); liveSessionRef.current = null; }
        if (processorRef.current) { processorRef.current.disconnect(); processorRef.current = null; }
        if (sourceRef.current) { sourceRef.current.disconnect(); sourceRef.current = null; }
        if (mediaStreamRef.current) { mediaStreamRef.current.getTracks().forEach(track => track.stop()); mediaStreamRef.current = null; }
        stopAudioPlayback();
        if (audioContextRef.current) { await audioContextRef.current.close(); audioContextRef.current = null; }
    } else {
        try {
            setMode(InterviewMode.VOICE);
            currentTurnTextRef.current = "";
            const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
            const ctx = new AudioContextClass({ sampleRate: 24000 });
            audioContextRef.current = ctx;
            nextStartTimeRef.current = ctx.currentTime;

            const stream = await navigator.mediaDevices.getUserMedia({ audio: { channelCount: 1 } });
            mediaStreamRef.current = stream;

            const session = await connectToLiveSession({
                persona,
                onOpen: () => setIsLiveConnected(true),
                onAudioData: (base64) => {
                    if (!audioContextRef.current) return;
                    try {
                        const buffer = decodeAudioData(base64, audioContextRef.current, 24000);
                        const source = audioContextRef.current.createBufferSource();
                        source.buffer = buffer;
                        source.connect(audioContextRef.current.destination);
                        const now = audioContextRef.current.currentTime;
                        const startTime = Math.max(now, nextStartTimeRef.current);
                        source.start(startTime);
                        nextStartTimeRef.current = startTime + buffer.duration;
                        source.onended = () => { const idx = audioSourcesRef.current.indexOf(source); if (idx > -1) audioSourcesRef.current.splice(idx, 1); };
                        audioSourcesRef.current.push(source);
                    } catch (e) { console.error(e); }
                },
                onTranscript: (text, isUser, isFinal) => {
                    if (isUser) updateLastMessage(text, Sender.USER);
                    else {
                        currentTurnTextRef.current += text;
                        updateLastMessage(currentTurnTextRef.current, Sender.AI);
                        if (isFinal) currentTurnTextRef.current = "";
                    }
                },
                onInterrupted: () => {
                    stopAudioPlayback();
                    nextStartTimeRef.current = audioContextRef.current?.currentTime || 0;
                    currentTurnTextRef.current = "";
                },
                onClose: () => setIsLiveConnected(false),
                onError: (err) => { console.error(err); toggleVoiceMode(); }
            });

            liveSessionRef.current = session;
            const source = ctx.createMediaStreamSource(stream);
            sourceRef.current = source;
            const processor = ctx.createScriptProcessor(4096, 1, 1);
            processorRef.current = processor;
            processor.onaudioprocess = (e) => {
                if (!liveSessionRef.current) return;
                const inputData = e.inputBuffer.getChannelData(0);
                session.sendAudioChunk(downsampleBuffer(inputData, ctx.sampleRate, 16000));
            };
            source.connect(processor);
            processor.connect(ctx.destination);
        } catch (e) { setMode(InterviewMode.TEXT); }
    }
  };

  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    try {
        let attachment: Attachment;
        if (file.type.startsWith('image/')) {
            const dataUrl = await new Promise<string>((resolve) => { const r = new FileReader(); r.onload = () => resolve(r.result as string); r.readAsDataURL(file); });
            attachment = { type: 'image', mimeType: file.type, data: dataUrl, fileName: file.name };
        } else {
            // Simplified PDF/Text logic
            const text = await new Promise<string>((resolve) => { const r = new FileReader(); r.onload = () => resolve(r.result as string); r.readAsText(file); });
            attachment = { type: 'file', mimeType: file.type, data: text, fileName: file.name };
            if (!resumeData && (text.includes("Experience") || text.includes("Education"))) {
                setResumeData({ data: text, mimeType: 'text/plain' });
                addMessage(Sender.SYSTEM, "Resume Context Loaded");
            }
        }
        setPendingAttachment(attachment);
    } catch (err: any) { addMessage(Sender.SYSTEM, "Upload Failed"); }
    finally { if (fileInputRef.current) fileInputRef.current.value = ''; }
  };

  return (
    <div className="h-[100dvh] bg-[#121212] text-[#E3E3E3] flex flex-col overflow-hidden font-sans">

      {/* 1. App Bar (Material Style) */}
      <header className="bg-[#1E1E1E] shadow-md px-4 py-3 flex items-center justify-between shrink-0 z-20 material-elevation-2 relative">
         <div className="flex items-center gap-3">
             <div className="bg-gradient-to-br from-blue-500 to-purple-600 w-8 h-8 rounded-lg flex items-center justify-center shadow-lg">
                <span className="material-symbols-rounded text-white text-[20px]">code_blocks</span>
             </div>
             <div>
                <h1 className="text-[16px] font-bold tracking-tight text-white leading-tight">Nexus AI</h1>
                <div className="flex items-center gap-1.5">
                   <span className={`w-1.5 h-1.5 rounded-full ${isLiveConnected ? 'bg-red-500 animate-pulse' : 'bg-green-500'}`}></span>
                   <span className="text-[10px] text-gray-400 font-medium">ONLINE</span>
                </div>
             </div>
         </div>

         <div className="flex items-center gap-2">
            {resumeData && <span className="material-symbols-rounded text-green-400 text-[20px]" title="Resume Loaded">description</span>}

            <button 
                onClick={() => setPersona(persona === Persona.INTERVIEWER ? Persona.TUTOR : Persona.INTERVIEWER)}
                className="bg-[#2C2C2C] text-[10px] font-bold px-3 py-1.5 rounded-full border border-[#3C3C3C] text-gray-300 active:bg-[#3C3C3C] transition-colors"
            >
                {persona} MODE
            </button>
         </div>
      </header>

      {/* 2. Body Area */}
      <div className="flex-1 relative overflow-hidden">

        {/* Chat Screen */}
        <div className={`absolute inset-0 flex flex-col transition-transform duration-300 ${activeTab === 'chat' ? 'translate-x-0' : '-translate-x-full'}`}>
           <div className={`flex-1 overflow-y-auto p-4 space-y-4 pb-24 bg-[#121212] ${mode === InterviewMode.VOICE ? 'pt-16' : ''}`}>
                {messages.length === 0 && (
                    <div className="flex flex-col items-center justify-center h-full text-gray-600 gap-4 opacity-50">
                        <span className="material-symbols-rounded text-6xl">forum</span>
                        <p className="text-sm font-medium">Start your interview session</p>
                    </div>
                )}
                {messages.map((msg) => (
                    <TerminalMessage key={msg.id} message={msg} onPlayAudio={playTTS} />
                ))}
                {isLoading && (
                    <div className="flex justify-start px-2 py-2">
                        <div className="bg-[#2C2C2C] px-4 py-2 rounded-full rounded-tl-sm flex gap-1 items-center">
                            <div className="w-1.5 h-1.5 bg-gray-400 rounded-full typing-dot"></div>
                            <div className="w-1.5 h-1.5 bg-gray-400 rounded-full typing-dot"></div>
                            <div className="w-1.5 h-1.5 bg-gray-400 rounded-full typing-dot"></div>
                        </div>
                    </div>
                )}
                <div ref={messagesEndRef} className="h-4" />
           </div>
        </div>

        {/* Code Screen */}
        <div className={`absolute inset-0 bg-[#0d1117] transition-transform duration-300 ${activeTab === 'code' ? 'translate-x-0' : 'translate-x-full'} ${mode === InterviewMode.VOICE ? 'pt-14' : ''}`}>
           <CodeEditor onReviewRequest={handleCodeReviewRequest} />
        </div>

        {/* Voice Active Status Bar (Non-blocking) */}
        {mode === InterviewMode.VOICE && (
            <div className="absolute top-4 left-4 right-4 z-40 animate-slide-up">
                <div className="bg-[#1E1E1E]/90 backdrop-blur-md border border-[#333] shadow-2xl rounded-2xl p-3 flex items-center justify-between">
                    <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-full bg-red-500/20 flex items-center justify-center animate-pulse">
                            <span className="material-symbols-rounded text-red-500">mic</span>
                        </div>
                        <div className="flex flex-col">
                            <span className="text-white text-sm font-medium">Live Interview</span>
                            <span className="text-gray-400 text-xs">{isLiveConnected ? 'Listening...' : 'Connecting...'}</span>
                        </div>
                    </div>

                    <button 
                        onClick={toggleVoiceMode}
                        className="w-10 h-10 rounded-full bg-red-600 hover:bg-red-700 flex items-center justify-center text-white shadow-lg transition-transform active:scale-95"
                    >
                        <span className="material-symbols-rounded">call_end</span>
                    </button>
                </div>
            </div>
        )}
      </div>

      {/* 3. Input Area (Always visible even in Voice Mode, allowing text/coding) */}
      <div className={`bg-[#1E1E1E] p-3 border-t border-[#2C2C2C] transition-transform duration-300 ${activeTab === 'chat' ? 'translate-y-0' : 'translate-y-full absolute bottom-0 w-full'}`}>
          {pendingAttachment && (
             <div className="mx-2 mb-2 p-2 bg-[#2C2C2C] rounded-lg flex items-center justify-between border border-[#3C3C3C]">
                 <div className="flex items-center gap-2 overflow-hidden">
                     <span className="material-symbols-rounded text-blue-400 text-sm">attachment</span>
                     <span className="text-xs text-gray-300 truncate">{pendingAttachment.fileName}</span>
                 </div>
                 <button onClick={() => setPendingAttachment(null)} className="text-gray-500 hover:text-red-400">
                     <span className="material-symbols-rounded text-sm">close</span>
                 </button>
             </div>
          )}

          <div className="flex items-end gap-2">
             <button onClick={() => fileInputRef.current?.click()} className="p-3 text-gray-400 hover:text-white rounded-full hover:bg-[#2C2C2C] transition-colors">
                 <span className="material-symbols-rounded">attach_file</span>
             </button>

             <button 
                onClick={stopAudioPlayback}
                className="p-3 text-red-400 hover:text-red-300 rounded-full hover:bg-[#2C2C2C] transition-colors"
                title="Stop Audio"
             >
                 <span className="material-symbols-rounded">stop_circle</span>
             </button>

             <input type="file" ref={fileInputRef} className="hidden" onChange={handleFileSelect} accept="image/*,.pdf,.txt,.js,.ts,.py" />

             <form onSubmit={(e) => handleTextSubmit(e)} className="flex-1 bg-[#2C2C2C] rounded-3xl border border-[#3C3C3C] focus-within:border-gray-500 transition-colors flex items-center px-4 py-2 min-h-[48px]">
                 <input 
                    type="text" 
                    value={inputValue}
                    onChange={(e) => setInputValue(e.target.value)}
                    placeholder="Message..."
                    className="bg-transparent border-none outline-none text-white w-full placeholder-gray-500 text-[15px]"
                    disabled={isLoading}
                 />
             </form>

             <button 
                onClick={(e) => inputValue.trim() ? handleTextSubmit(e, inputValue) : toggleVoiceMode()}
                className={`p-3 rounded-full shadow-lg transition-transform active:scale-95 flex items-center justify-center ${inputValue.trim() ? 'bg-blue-600 text-white' : 'bg-[#2C2C2C] text-white border border-[#3C3C3C]'}`}
             >
                 <span className="material-symbols-rounded">
                    {inputValue.trim() ? 'send' : 'mic'}
                 </span>
             </button>
          </div>
      </div>

      {/* 4. Bottom Navigation Bar */}
      <nav className="bg-[#1E1E1E] border-t border-[#2C2C2C] pb-safe">
         <div className="flex justify-around items-center h-16">
             <button 
               onClick={() => setActiveTab('chat')} 
               className={`flex flex-col items-center gap-1 w-full h-full justify-center ${activeTab === 'chat' ? 'text-blue-400' : 'text-gray-500'}`}
             >
                <span className={`material-symbols-rounded transition-transform ${activeTab === 'chat' ? 'scale-110 fill-current' : ''}`}>chat_bubble</span>
                <span className="text-[10px] font-medium">Interview</span>
             </button>

             <button 
               onClick={() => setActiveTab('code')}
               className={`flex flex-col items-center gap-1 w-full h-full justify-center ${activeTab === 'code' ? 'text-blue-400' : 'text-gray-500'}`}
             >
                <span className={`material-symbols-rounded transition-transform ${activeTab === 'code' ? 'scale-110 fill-current' : ''}`}>terminal</span>
                <span className="text-[10px] font-medium">Workspace</span>
             </button>
         </div>
      </nav>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { v4 as uuidv4 } from 'uuid';
import * as pdfjsLib from 'pdfjs-dist';
import { 
  generateInterviewQuestion, 
  generateImage,
  connectToLiveSession,
  reviewCodeWithAI,
  ResumeData
} from './services/geminiService';
import { decodeAudioData, downsampleBuffer } from './utils/audioUtils';
import { TerminalMessage } from './components/TerminalMessage';
import { CodeEditor } from './components/CodeEditor';
import { Message, Sender, InterviewMode, Persona, Attachment } from './types';

const App: React.FC = () => {
  // Navigation State
  const [activeTab, setActiveTab] = useState<'chat' | 'code'>('chat');

  // App Logic State
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [mode, setMode] = useState<InterviewMode>(InterviewMode.TEXT);
  const [persona, setPersona] = useState<Persona>(Persona.INTERVIEWER);
  const [isLiveConnected, setIsLiveConnected] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [tokenMissing, setTokenMissing] = useState(false);

  // Data State
  const [resumeData, setResumeData] = useState<ResumeData | undefined>(undefined);
  const [pendingAttachment, setPendingAttachment] = useState<Attachment | null>(null);

  // Refs
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const synthRef = useRef<SpeechSynthesis>(window.speechSynthesis);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Audio Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const sourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const liveSessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef<number>(0);
  const audioSourcesRef = useRef<AudioBufferSourceNode[]>([]);
  const currentTurnTextRef = useRef<string>("");

  // Init
  useEffect(() => {
    // PDF Worker
    const pdfjs = pdfjsLib as any;
    const workerOptions = pdfjs.GlobalWorkerOptions || pdfjs.default?.GlobalWorkerOptions || (window as any).pdfjsLib?.GlobalWorkerOptions;
    if (workerOptions) workerOptions.workerSrc = "https://unpkg.com/pdfjs-dist@3.11.174/build/pdf.worker.min.js";

    const key = process.env.API_KEY;
    if (!key || key.trim() === '') {
        setTokenMissing(true);
        addMessage(Sender.SYSTEM, "Configuration Error: API_KEY is missing.");
    } else {
        setTimeout(() => addMessage(Sender.AI, "Welcome. I am your Nexus AI Assistant. Ready for your technical assessment."), 500);
    }

    return () => { if (audioContextRef.current) audioContextRef.current.close(); };
  }, []);

  // Auto-scroll
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isLoading, pendingAttachment, activeTab]);

  const addMessage = (sender: Sender, text: string, grounding?: any[], isThinking = false, imageData?: string, attachment?: Attachment) => {
    const id = uuidv4();
    setMessages(prev => [...prev, {
      id,
      sender,
      text,
      timestamp: Date.now(),
      grounding,
      isThinking,
      imageData,
      attachment
    }]);
    return id;
  };

  const updateLastMessage = (text: string, sender: Sender) => {
      setMessages(prev => {
          const last = prev[prev.length - 1];
          if (last && last.sender === sender) {
              return [...prev.slice(0, -1), { ...last, text: text }];
          } else {
              return [...prev, { id: uuidv4(), sender, text, timestamp: Date.now() }];
          }
      });
  };

  const playTTS = (text: string) => {
    if (!synthRef.current || mode === InterviewMode.VOICE) return;
    synthRef.current.cancel();
    const utterance = new SpeechSynthesisUtterance(text.replace(/[*#`_]/g, ''));
    const voices = synthRef.current.getVoices();
    const preferred = voices.find(v => v.name.includes('Google US English') || v.lang === 'en-US');
    if (preferred) utterance.voice = preferred;
    synthRef.current.speak(utterance);
  };

  // --- Voice Logic ---
  const stopAudioPlayback = () => {
      // Stop Web Audio API sources (Live API)
      audioSourcesRef.current.forEach(source => { try { source.stop(); } catch (e) {} });
      audioSourcesRef.current = [];

      // Stop Browser TTS
      if (synthRef.current) {
          synthRef.current.cancel();
      }
  };

  const handleTextSubmit = async (e?: React.FormEvent, overrideText?: string) => {
    e?.preventDefault();
    const textToSend = overrideText || inputValue;
    if (!textToSend.trim() && !pendingAttachment) return;

    const attachment = pendingAttachment;
    setPendingAttachment(null);
    if (!overrideText) setInputValue('');

    addMessage(Sender.USER, textToSend, undefined, undefined, undefined, attachment || undefined);
    if (tokenMissing) return;

    if (textToSend.toLowerCase() === '/code') {
        setActiveTab('code');
        addMessage(Sender.SYSTEM, "Switched to Workspace");
        return;
    }

    setIsLoading(true);

    const history = messages.slice(-6).filter(m => !m.imageData).map(m => `${m.sender}: ${m.text}`).join('\n');
    let promptToSend = textToSend;
    let imageContext: { mimeType: string; data: string } | undefined;

    if (attachment) {
      if (attachment.type === 'image') {
        imageContext = { mimeType: attachment.mimeType, data: attachment.data };
        promptToSend += `\n[User attached an image]`;
      } else {
        promptToSend += `\n\n[FILE: ${attachment.fileName}]\n${attachment.data}`;
      }
    }

    try {
        const response = await generateInterviewQuestion(
            history + `\nUSER: ${promptToSend}`,
            persona,
            false,
            resumeData,
            imageContext
        );

        setIsLoading(false);
        const msgId = addMessage(Sender.AI, response.text, response.grounding);
        playTTS(response.text);

        if (response.isCodingChallenge) {
          setActiveTab('code');
          addMessage(Sender.SYSTEM, "Coding Challenge Started - Workspace Active");
        }

        if (response.imagePrompt) {
            generateImage(response.imagePrompt)
                .then(url => setMessages(prev => prev.map(m => m.id === msgId ? { ...m, imageData: url } : m)))
                .catch(console.error);
        }
    } catch (e: any) {
        setIsLoading(false);
        addMessage(Sender.SYSTEM, `Error: ${e.message}`);
    }
  };

  const handleCodeReviewRequest = async (code: string, language: string) => {
    setActiveTab('chat');
    addMessage(Sender.USER, `Submitted ${language} solution for review.`);
    setIsLoading(true);
    addMessage(Sender.SYSTEM, "Analyzing Solution...");
    try {
        const feedback = await reviewCodeWithAI(language, code);
        setIsLoading(false);
        addMessage(Sender.AI, feedback);
        playTTS(feedback);
    } catch (e: any) {
        setIsLoading(false);
        addMessage(Sender.SYSTEM, `Review Error: ${e.message}`);
    }
  };

  const toggleVoiceMode = async () => {
    if (mode === InterviewMode.VOICE) {
        setMode(InterviewMode.TEXT);
        setIsLiveConnected(false);
        if (liveSessionRef.current) { liveSessionRef.current.disconnect(); liveSessionRef.current = null; }
        if (processorRef.current) { processorRef.current.disconnect(); processorRef.current = null; }
        if (sourceRef.current) { sourceRef.current.disconnect(); sourceRef.current = null; }
        if (mediaStreamRef.current) { mediaStreamRef.current.getTracks().forEach(track => track.stop()); mediaStreamRef.current = null; }
        stopAudioPlayback();
        if (audioContextRef.current) { await audioContextRef.current.close(); audioContextRef.current = null; }
    } else {
        try {
            setMode(InterviewMode.VOICE);
            currentTurnTextRef.current = "";
            const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
            const ctx = new AudioContextClass({ sampleRate: 24000 });
            audioContextRef.current = ctx;
            nextStartTimeRef.current = ctx.currentTime;

            const stream = await navigator.mediaDevices.getUserMedia({ audio: { channelCount: 1 } });
            mediaStreamRef.current = stream;

            const session = await connectToLiveSession({
                persona,
                onOpen: () => setIsLiveConnected(true),
                onAudioData: (base64) => {
                    if (!audioContextRef.current) return;
                    try {
                        const buffer = decodeAudioData(base64, audioContextRef.current, 24000);
                        const source = audioContextRef.current.createBufferSource();
                        source.buffer = buffer;
                        source.connect(audioContextRef.current.destination);
                        const now = audioContextRef.current.currentTime;
                        const startTime = Math.max(now, nextStartTimeRef.current);
                        source.start(startTime);
                        nextStartTimeRef.current = startTime + buffer.duration;
                        source.onended = () => { const idx = audioSourcesRef.current.indexOf(source); if (idx > -1) audioSourcesRef.current.splice(idx, 1); };
                        audioSourcesRef.current.push(source);
                    } catch (e) { console.error(e); }
                },
                onTranscript: (text, isUser, isFinal) => {
                    if (isUser) updateLastMessage(text, Sender.USER);
                    else {
                        currentTurnTextRef.current += text;
                        updateLastMessage(currentTurnTextRef.current, Sender.AI);
                        if (isFinal) currentTurnTextRef.current = "";
                    }
                },
                onInterrupted: () => {
                    stopAudioPlayback();
                    nextStartTimeRef.current = audioContextRef.current?.currentTime || 0;
                    currentTurnTextRef.current = "";
                },
                onClose: () => setIsLiveConnected(false),
                onError: (err) => { console.error(err); toggleVoiceMode(); }
            });

            liveSessionRef.current = session;
            const source = ctx.createMediaStreamSource(stream);
            sourceRef.current = source;
            const processor = ctx.createScriptProcessor(4096, 1, 1);
            processorRef.current = processor;
            processor.onaudioprocess = (e) => {
                if (!liveSessionRef.current) return;
                const inputData = e.inputBuffer.getChannelData(0);
                session.sendAudioChunk(downsampleBuffer(inputData, ctx.sampleRate, 16000));
            };
            source.connect(processor);
            processor.connect(ctx.destination);
        } catch (e) { setMode(InterviewMode.TEXT); }
    }
  };

  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    try {
        let attachment: Attachment;
        if (file.type.startsWith('image/')) {
            const dataUrl = await new Promise<string>((resolve) => { const r = new FileReader(); r.onload = () => resolve(r.result as string); r.readAsDataURL(file); });
            attachment = { type: 'image', mimeType: file.type, data: dataUrl, fileName: file.name };
        } else {
            // Simplified PDF/Text logic
            const text = await new Promise<string>((resolve) => { const r = new FileReader(); r.onload = () => resolve(r.result as string); r.readAsText(file); });
            attachment = { type: 'file', mimeType: file.type, data: text, fileName: file.name };
            if (!resumeData && (text.includes("Experience") || text.includes("Education"))) {
                setResumeData({ data: text, mimeType: 'text/plain' });
                addMessage(Sender.SYSTEM, "Resume Context Loaded");
            }
        }
        setPendingAttachment(attachment);
    } catch (err: any) { addMessage(Sender.SYSTEM, "Upload Failed"); }
    finally { if (fileInputRef.current) fileInputRef.current.value = ''; }
  };

  return (
    <div className="h-[100dvh] bg-[#121212] text-[#E3E3E3] flex flex-col overflow-hidden font-sans">

      {/* 1. App Bar (Material Style) */}
      <header className="bg-[#1E1E1E] shadow-md px-4 py-3 flex items-center justify-between shrink-0 z-20 material-elevation-2 relative">
         <div className="flex items-center gap-3">
             <div className="bg-gradient-to-br from-blue-500 to-purple-600 w-8 h-8 rounded-lg flex items-center justify-center shadow-lg">
                <span className="material-symbols-rounded text-white text-[20px]">code_blocks</span>
             </div>
             <div>
                <h1 className="text-[16px] font-bold tracking-tight text-white leading-tight">Nexus AI</h1>
                <div className="flex items-center gap-1.5">
                   <span className={`w-1.5 h-1.5 rounded-full ${isLiveConnected ? 'bg-red-500 animate-pulse' : 'bg-green-500'}`}></span>
                   <span className="text-[10px] text-gray-400 font-medium">ONLINE</span>
                </div>
             </div>
         </div>

         <div className="flex items-center gap-2">
            {resumeData && <span className="material-symbols-rounded text-green-400 text-[20px]" title="Resume Loaded">description</span>}

            <button 
                onClick={() => setPersona(persona === Persona.INTERVIEWER ? Persona.TUTOR : Persona.INTERVIEWER)}
                className="bg-[#2C2C2C] text-[10px] font-bold px-3 py-1.5 rounded-full border border-[#3C3C3C] text-gray-300 active:bg-[#3C3C3C] transition-colors"
            >
                {persona} MODE
            </button>
         </div>
      </header>

      {/* 2. Body Area */}
      <div className="flex-1 relative overflow-hidden">

        {/* Chat Screen */}
        <div className={`absolute inset-0 flex flex-col transition-transform duration-300 ${activeTab === 'chat' ? 'translate-x-0' : '-translate-x-full'}`}>
           <div className={`flex-1 overflow-y-auto p-4 space-y-4 pb-24 bg-[#121212] ${mode === InterviewMode.VOICE ? 'pt-16' : ''}`}>
                {messages.length === 0 && (
                    <div className="flex flex-col items-center justify-center h-full text-gray-600 gap-4 opacity-50">
                        <span className="material-symbols-rounded text-6xl">forum</span>
                        <p className="text-sm font-medium">Start your interview session</p>
                    </div>
                )}
                {messages.map((msg) => (
                    <TerminalMessage key={msg.id} message={msg} onPlayAudio={playTTS} />
                ))}
                {isLoading && (
                    <div className="flex justify-start px-2 py-2">
                        <div className="bg-[#2C2C2C] px-4 py-2 rounded-full rounded-tl-sm flex gap-1 items-center">
                            <div className="w-1.5 h-1.5 bg-gray-400 rounded-full typing-dot"></div>
                            <div className="w-1.5 h-1.5 bg-gray-400 rounded-full typing-dot"></div>
                            <div className="w-1.5 h-1.5 bg-gray-400 rounded-full typing-dot"></div>
                        </div>
                    </div>
                )}
                <div ref={messagesEndRef} className="h-4" />
           </div>
        </div>

        {/* Code Screen */}
        <div className={`absolute inset-0 bg-[#0d1117] transition-transform duration-300 ${activeTab === 'code' ? 'translate-x-0' : 'translate-x-full'} ${mode === InterviewMode.VOICE ? 'pt-14' : ''}`}>
           <CodeEditor onReviewRequest={handleCodeReviewRequest} />
        </div>

        {/* Voice Active Status Bar (Non-blocking) */}
        {mode === InterviewMode.VOICE && (
            <div className="absolute top-4 left-4 right-4 z-40 animate-slide-up">
                <div className="bg-[#1E1E1E]/90 backdrop-blur-md border border-[#333] shadow-2xl rounded-2xl p-3 flex items-center justify-between">
                    <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-full bg-red-500/20 flex items-center justify-center animate-pulse">
                            <span className="material-symbols-rounded text-red-500">mic</span>
                        </div>
                        <div className="flex flex-col">
                            <span className="text-white text-sm font-medium">Live Interview</span>
                            <span className="text-gray-400 text-xs">{isLiveConnected ? 'Listening...' : 'Connecting...'}</span>
                        </div>
                    </div>

                    <button 
                        onClick={toggleVoiceMode}
                        className="w-10 h-10 rounded-full bg-red-600 hover:bg-red-700 flex items-center justify-center text-white shadow-lg transition-transform active:scale-95"
                    >
                        <span className="material-symbols-rounded">call_end</span>
                    </button>
                </div>
            </div>
        )}
      </div>

      {/* 3. Input Area (Always visible even in Voice Mode, allowing text/coding) */}
      <div className={`bg-[#1E1E1E] p-3 border-t border-[#2C2C2C] transition-transform duration-300 ${activeTab === 'chat' ? 'translate-y-0' : 'translate-y-full absolute bottom-0 w-full'}`}>
          {pendingAttachment && (
             <div className="mx-2 mb-2 p-2 bg-[#2C2C2C] rounded-lg flex items-center justify-between border border-[#3C3C3C]">
                 <div className="flex items-center gap-2 overflow-hidden">
                     <span className="material-symbols-rounded text-blue-400 text-sm">attachment</span>
                     <span className="text-xs text-gray-300 truncate">{pendingAttachment.fileName}</span>
                 </div>
                 <button onClick={() => setPendingAttachment(null)} className="text-gray-500 hover:text-red-400">
                     <span className="material-symbols-rounded text-sm">close</span>
                 </button>
             </div>
          )}

          <div className="flex items-center gap-2">
             <button onClick={() => fileInputRef.current?.click()} className="p-3 text-gray-400 hover:text-white rounded-full hover:bg-[#2C2C2C] transition-colors flex-shrink-0">
                 <span className="material-symbols-rounded">attach_file</span>
             </button>

             <button 
                onClick={stopAudioPlayback}
                className="p-3 text-red-400 hover:text-red-300 rounded-full hover:bg-[#2C2C2C] transition-colors flex-shrink-0"
                title="Stop Audio"
             >
                 <span className="material-symbols-rounded">stop_circle</span>
             </button>

             <input type="file" ref={fileInputRef} className="hidden" onChange={handleFileSelect} accept="image/*,.pdf,.txt,.js,.ts,.py" />

             <form onSubmit={(e) => handleTextSubmit(e)} className="flex-1 bg-[#2C2C2C] rounded-3xl border border-[#3C3C3C] focus-within:border-gray-500 transition-colors flex items-center px-4 py-2 min-h-[48px]">
                 <input 
                    type="text" 
                    value={inputValue}
                    onChange={(e) => setInputValue(e.target.value)}
                    placeholder="Message..."
                    className="bg-transparent border-none outline-none text-white w-full placeholder-gray-500 text-[15px]"
                    disabled={isLoading}
                 />
             </form>

             <button 
                onClick={(e) => inputValue.trim() ? handleTextSubmit(e, inputValue) : toggleVoiceMode()}
                className={`p-3 rounded-full shadow-lg transition-transform active:scale-95 flex items-center justify-center flex-shrink-0 ${inputValue.trim() ? 'bg-blue-600 text-white' : 'bg-[#2C2C2C] text-white border border-[#3C3C3C]'}`}
             >
                 <span className="material-symbols-rounded">
                    {inputValue.trim() ? 'send' : 'mic'}
                 </span>
             </button>
          </div>
      </div>

      {/* 4. Bottom Navigation Bar */}
      <nav className="bg-[#1E1E1E] border-t border-[#2C2C2C] pb-safe">
         <div className="flex justify-around items-center h-16">
             <button 
               onClick={() => setActiveTab('chat')} 
               className={`flex flex-col items-center gap-1 w-full h-full justify-center ${activeTab === 'chat' ? 'text-blue-400' : 'text-gray-500'}`}
             >
                <span className={`material-symbols-rounded transition-transform ${activeTab === 'chat' ? 'scale-110 fill-current' : ''}`}>chat_bubble</span>
                <span className="text-[10px] font-medium">Interview</span>
             </button>

             <button 
               onClick={() => setActiveTab('code')}
               className={`flex flex-col items-center gap-1 w-full h-full justify-center ${activeTab === 'code' ? 'text-blue-400' : 'text-gray-500'}`}
             >
                <span className={`material-symbols-rounded transition-transform ${activeTab === 'code' ? 'scale-110 fill-current' : ''}`}>terminal</span>
                <span className="text-[10px] font-medium">Workspace</span>
             </button>
         </div>
      </nav>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { v4 as uuidv4 } from 'uuid';
import * as pdfjsLib from 'pdfjs-dist';
import { 
  generateInterviewQuestion, 
  generateImage,
  connectToLiveSession,
  reviewCodeWithAI,
  ResumeData
} from './services/geminiService';
import { decodeAudioData, downsampleBuffer } from './utils/audioUtils';
import { TerminalMessage } from './components/TerminalMessage';
import { CodeEditor } from './components/CodeEditor';
import { Message, Sender, InterviewMode, Persona, Attachment } from './types';

const App: React.FC = () => {
  // Navigation State
  const [activeTab, setActiveTab] = useState<'chat' | 'code'>('chat');

  // App Logic State
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [mode, setMode] = useState<InterviewMode>(InterviewMode.TEXT);
  const [persona, setPersona] = useState<Persona>(Persona.INTERVIEWER);
  const [isLiveConnected, setIsLiveConnected] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [tokenMissing, setTokenMissing] = useState(false);

  // Data State
  const [resumeData, setResumeData] = useState<ResumeData | undefined>(undefined);
  const [pendingAttachment, setPendingAttachment] = useState<Attachment | null>(null);

  // Refs
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const synthRef = useRef<SpeechSynthesis>(window.speechSynthesis);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Audio Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const sourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const liveSessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef<number>(0);
  const audioSourcesRef = useRef<AudioBufferSourceNode[]>([]);
  const currentTurnTextRef = useRef<string>("");

  // Init
  useEffect(() => {
    // PDF Worker
    const pdfjs = pdfjsLib as any;
    const workerOptions = pdfjs.GlobalWorkerOptions || pdfjs.default?.GlobalWorkerOptions || (window as any).pdfjsLib?.GlobalWorkerOptions;
    if (workerOptions) workerOptions.workerSrc = "https://unpkg.com/pdfjs-dist@3.11.174/build/pdf.worker.min.js";

    const key = process.env.API_KEY;
    if (!key || key.trim() === '') {
        setTokenMissing(true);
        addMessage(Sender.SYSTEM, "Configuration Error: API_KEY is missing.");
    } else {
        setTimeout(() => addMessage(Sender.AI, "Welcome. I am your Nexus AI Assistant. Ready for your technical assessment."), 500);
    }

    return () => { if (audioContextRef.current) audioContextRef.current.close(); };
  }, []);

  // Auto-scroll
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isLoading, pendingAttachment, activeTab]);

  const addMessage = (sender: Sender, text: string, grounding?: any[], isThinking = false, imageData?: string, attachment?: Attachment) => {
    const id = uuidv4();
    setMessages(prev => [...prev, {
      id,
      sender,
      text,
      timestamp: Date.now(),
      grounding,
      isThinking,
      imageData,
      attachment
    }]);
    return id;
  };

  const updateLastMessage = (text: string, sender: Sender) => {
      setMessages(prev => {
          const last = prev[prev.length - 1];
          if (last && last.sender === sender) {
              return [...prev.slice(0, -1), { ...last, text: text }];
          } else {
              return [...prev, { id: uuidv4(), sender, text, timestamp: Date.now() }];
          }
      });
  };

  const playTTS = (text: string) => {
    if (!synthRef.current || mode === InterviewMode.VOICE) return;
    synthRef.current.cancel();
    const utterance = new SpeechSynthesisUtterance(text.replace(/[*#`_]/g, ''));
    const voices = synthRef.current.getVoices();
    const preferred = voices.find(v => v.name.includes('Google US English') || v.lang === 'en-US');
    if (preferred) utterance.voice = preferred;
    synthRef.current.speak(utterance);
  };

  // --- Voice Logic ---
  const stopAudioPlayback = () => {
      // Stop Web Audio API sources (Live API)
      audioSourcesRef.current.forEach(source => { try { source.stop(); } catch (e) {} });
      audioSourcesRef.current = [];

      // Stop Browser TTS
      if (synthRef.current) {
          synthRef.current.cancel();
      }
  };

  const handleTextSubmit = async (e?: React.FormEvent, overrideText?: string) => {
    e?.preventDefault();
    const textToSend = overrideText || inputValue;
    if (!textToSend.trim() && !pendingAttachment) return;

    const attachment = pendingAttachment;
    setPendingAttachment(null);
    if (!overrideText) setInputValue('');

    addMessage(Sender.USER, textToSend, undefined, undefined, undefined, attachment || undefined);
    if (tokenMissing) return;

    if (textToSend.toLowerCase() === '/code') {
        setActiveTab('code');
        addMessage(Sender.SYSTEM, "Switched to Workspace");
        return;
    }

    setIsLoading(true);

    const history = messages.slice(-6).filter(m => !m.imageData).map(m => `${m.sender}: ${m.text}`).join('\n');
    let promptToSend = textToSend;
    let imageContext: { mimeType: string; data: string } | undefined;

    if (attachment) {
      if (attachment.type === 'image') {
        imageContext = { mimeType: attachment.mimeType, data: attachment.data };
        promptToSend += `\n[User attached an image]`;
      } else {
        promptToSend += `\n\n[FILE: ${attachment.fileName}]\n${attachment.data}`;
      }
    }

    try {
        const response = await generateInterviewQuestion(
            history + `\nUSER: ${promptToSend}`,
            persona,
            false,
            resumeData,
            imageContext
        );

        setIsLoading(false);
        const msgId = addMessage(Sender.AI, response.text, response.grounding);
        playTTS(response.text);

        if (response.isCodingChallenge) {
          setActiveTab('code');
          addMessage(Sender.SYSTEM, "Coding Challenge Started - Workspace Active");
        }

        if (response.imagePrompt) {
            generateImage(response.imagePrompt)
                .then(url => setMessages(prev => prev.map(m => m.id === msgId ? { ...m, imageData: url } : m)))
                .catch(console.error);
        }
    } catch (e: any) {
        setIsLoading(false);
        addMessage(Sender.SYSTEM, `Error: ${e.message}`);
    }
  };

  const handleCodeReviewRequest = async (code: string, language: string) => {
    setActiveTab('chat');
    addMessage(Sender.USER, `Submitted ${language} solution for review.`);
    setIsLoading(true);
    addMessage(Sender.SYSTEM, "Analyzing Solution...");
    try {
        const feedback = await reviewCodeWithAI(language, code);
        setIsLoading(false);
        addMessage(Sender.AI, feedback);
        playTTS(feedback);
    } catch (e: any) {
        setIsLoading(false);
        addMessage(Sender.SYSTEM, `Review Error: ${e.message}`);
    }
  };

  const toggleVoiceMode = async () => {
    if (mode === InterviewMode.VOICE) {
        setMode(InterviewMode.TEXT);
        setIsLiveConnected(false);
        if (liveSessionRef.current) { liveSessionRef.current.disconnect(); liveSessionRef.current = null; }
        if (processorRef.current) { processorRef.current.disconnect(); processorRef.current = null; }
        if (sourceRef.current) { sourceRef.current.disconnect(); sourceRef.current = null; }
        if (mediaStreamRef.current) { mediaStreamRef.current.getTracks().forEach(track => track.stop()); mediaStreamRef.current = null; }
        stopAudioPlayback();
        if (audioContextRef.current) { await audioContextRef.current.close(); audioContextRef.current = null; }
    } else {
        try {
            setMode(InterviewMode.VOICE);
            currentTurnTextRef.current = "";
            const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
            const ctx = new AudioContextClass({ sampleRate: 24000 });
            audioContextRef.current = ctx;
            nextStartTimeRef.current = ctx.currentTime;

            const stream = await navigator.mediaDevices.getUserMedia({ audio: { channelCount: 1 } });
            mediaStreamRef.current = stream;

            const session = await connectToLiveSession({
                persona,
                onOpen: () => setIsLiveConnected(true),
                onAudioData: (base64) => {
                    if (!audioContextRef.current) return;
                    try {
                        const buffer = decodeAudioData(base64, audioContextRef.current, 24000);
                        const source = audioContextRef.current.createBufferSource();
                        source.buffer = buffer;
                        source.connect(audioContextRef.current.destination);
                        const now = audioContextRef.current.currentTime;
                        const startTime = Math.max(now, nextStartTimeRef.current);
                        source.start(startTime);
                        nextStartTimeRef.current = startTime + buffer.duration;
                        source.onended = () => { const idx = audioSourcesRef.current.indexOf(source); if (idx > -1) audioSourcesRef.current.splice(idx, 1); };
                        audioSourcesRef.current.push(source);
                    } catch (e) { console.error(e); }
                },
                onTranscript: (text, isUser, isFinal) => {
                    if (isUser) updateLastMessage(text, Sender.USER);
                    else {
                        currentTurnTextRef.current += text;
                        updateLastMessage(currentTurnTextRef.current, Sender.AI);
                        if (isFinal) currentTurnTextRef.current = "";
                    }
                },
                onInterrupted: () => {
                    stopAudioPlayback();
                    nextStartTimeRef.current = audioContextRef.current?.currentTime || 0;
                    currentTurnTextRef.current = "";
                },
                onClose: () => setIsLiveConnected(false),
                onError: (err) => { console.error(err); toggleVoiceMode(); }
            });

            liveSessionRef.current = session;
            const source = ctx.createMediaStreamSource(stream);
            sourceRef.current = source;
            const processor = ctx.createScriptProcessor(4096, 1, 1);
            processorRef.current = processor;
            processor.onaudioprocess = (e) => {
                if (!liveSessionRef.current) return;
                const inputData = e.inputBuffer.getChannelData(0);
                session.sendAudioChunk(downsampleBuffer(inputData, ctx.sampleRate, 16000));
            };
            source.connect(processor);
            processor.connect(ctx.destination);
        } catch (e) { setMode(InterviewMode.TEXT); }
    }
  };

  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    try {
        let attachment: Attachment;
        if (file.type.startsWith('image/')) {
            const dataUrl = await new Promise<string>((resolve) => { const r = new FileReader(); r.onload = () => resolve(r.result as string); r.readAsDataURL(file); });
            attachment = { type: 'image', mimeType: file.type, data: dataUrl, fileName: file.name };
        } else {
            // Simplified PDF/Text logic
            const text = await new Promise<string>((resolve) => { const r = new FileReader(); r.onload = () => resolve(r.result as string); r.readAsText(file); });
            attachment = { type: 'file', mimeType: file.type, data: text, fileName: file.name };
            if (!resumeData && (text.includes("Experience") || text.includes("Education"))) {
                setResumeData({ data: text, mimeType: 'text/plain' });
                addMessage(Sender.SYSTEM, "Resume Context Loaded");
            }
        }
        setPendingAttachment(attachment);
    } catch (err: any) { addMessage(Sender.SYSTEM, "Upload Failed"); }
    finally { if (fileInputRef.current) fileInputRef.current.value = ''; }
  };

  return (
    <div className="h-[100dvh] bg-[#121212] text-[#E3E3E3] flex flex-col overflow-hidden font-sans">

      {/* 1. App Bar (Material Style) */}
      <header className="bg-[#1E1E1E] shadow-md px-4 py-3 flex items-center justify-between shrink-0 z-20 material-elevation-2 relative min-h-[64px]">
         {mode === InterviewMode.VOICE ? (
             <div className="flex items-center justify-between w-full animate-slide-up">
                <div className="flex items-center gap-3">
                     <div className="w-10 h-10 rounded-full bg-red-500/20 flex items-center justify-center animate-pulse">
                        <span className="material-symbols-rounded text-red-500 text-[24px]">mic</span>
                     </div>
                     <div className="flex flex-col">
                        <h1 className="text-[16px] font-bold tracking-tight text-white leading-tight">Live Interview</h1>
                        <span className="text-[10px] text-red-400 font-medium tracking-wide uppercase">{isLiveConnected ? 'Listening' : 'Connecting...'}</span>
                     </div>
                </div>

                <button 
                    onClick={toggleVoiceMode}
                    className="bg-red-600/10 hover:bg-red-600/20 text-red-500 border border-red-600/50 px-4 py-2 rounded-full text-xs font-bold flex items-center gap-2 transition-all active:scale-95"
                >
                    <span className="material-symbols-rounded text-[18px]">call_end</span>
                    <span>END</span>
                </button>
             </div>
         ) : (
             <>
                 <div className="flex items-center gap-3">
                     <div className="bg-gradient-to-br from-blue-500 to-purple-600 w-8 h-8 rounded-lg flex items-center justify-center shadow-lg">
                        <span className="material-symbols-rounded text-white text-[20px]">code_blocks</span>
                     </div>
                     <div>
                        <h1 className="text-[16px] font-bold tracking-tight text-white leading-tight">Nexus AI</h1>
                        <div className="flex items-center gap-1.5">
                           <span className="w-1.5 h-1.5 rounded-full bg-green-500"></span>
                           <span className="text-[10px] text-gray-400 font-medium">ONLINE</span>
                        </div>
                     </div>
                 </div>

                 <div className="flex items-center gap-2">
                    {resumeData && <span className="material-symbols-rounded text-green-400 text-[20px]" title="Resume Loaded">description</span>}

                    <button 
                        onClick={() => setPersona(persona === Persona.INTERVIEWER ? Persona.TUTOR : Persona.INTERVIEWER)}
                        className="bg-[#2C2C2C] text-[10px] font-bold px-3 py-1.5 rounded-full border border-[#3C3C3C] text-gray-300 active:bg-[#3C3C3C] transition-colors"
                    >
                        {persona} MODE
                    </button>
                 </div>
             </>
         )}
      </header>

      {/* 2. Body Area */}
      <div className="flex-1 relative overflow-hidden">

