import React, { useState, useEffect, useRef } from 'react';
import { v4 as uuidv4 } from 'uuid';
import * as pdfjsLib from 'pdfjs-dist';
import { 
  generateInterviewQuestion, 
  generateImage,
  connectToLiveSession,
  reviewCodeWithAI,
  ResumeData
} from './services/geminiService';
import { decodeAudioData, downsampleBuffer } from './utils/audioUtils';
import { TerminalMessage } from './components/TerminalMessage';
import { CodeEditor } from './components/CodeEditor';
import { Message, Sender, InterviewMode, Persona, Attachment } from './types';

const App: React.FC = () => {
  // Navigation State
  const [activeTab, setActiveTab] = useState<'chat' | 'code'>('chat');

  // App Logic State
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [mode, setMode] = useState<InterviewMode>(InterviewMode.TEXT);
  const [persona, setPersona] = useState<Persona>(Persona.INTERVIEWER);
  const [isLiveConnected, setIsLiveConnected] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [tokenMissing, setTokenMissing] = useState(false);

  // Data State
  const [resumeData, setResumeData] = useState<ResumeData | undefined>(undefined);
  const [pendingAttachment, setPendingAttachment] = useState<Attachment | null>(null);

  // Refs
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const synthRef = useRef<SpeechSynthesis>(window.speechSynthesis);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Audio Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const sourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const liveSessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef<number>(0);
  const audioSourcesRef = useRef<AudioBufferSourceNode[]>([]);
  const currentTurnTextRef = useRef<string>("");

  // Init
  useEffect(() => {
    // PDF Worker
    const pdfjs = pdfjsLib as any;
    const workerOptions = pdfjs.GlobalWorkerOptions || pdfjs.default?.GlobalWorkerOptions || (window as any).pdfjsLib?.GlobalWorkerOptions;
    if (workerOptions) workerOptions.workerSrc = "https://unpkg.com/pdfjs-dist@3.11.174/build/pdf.worker.min.js";

    const key = process.env.API_KEY;
    if (!key || key.trim() === '') {
        setTokenMissing(true);
        addMessage(Sender.SYSTEM, "Configuration Error: API_KEY is missing.");
    } else {
        setTimeout(() => addMessage(Sender.AI, "Welcome. I am your Nexus AI Assistant. Ready for your technical assessment."), 100);
    }

    return () => { if (audioContextRef.current) audioContextRef.current.close(); };
  }, []);

  // Auto-scroll
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isLoading, pendingAttachment, activeTab]);

  const addMessage = (sender: Sender, text: string, grounding?: any[], isThinking = false, imageData?: string, attachment?: Attachment) => {
    const id = uuidv4();
    setMessages(prev => [...prev, {
      id,
      sender,
      text,
      timestamp: Date.now(),
      grounding,
      isThinking,
      imageData,
      attachment
    }]);
    return id;
  };

  const updateLastMessage = (text: string, sender: Sender) => {
      setMessages(prev => {
          const last = prev[prev.length - 1];
          if (last && last.sender === sender) {
              return [...prev.slice(0, -1), { ...last, text: text }];
          } else {
              return [...prev, { id: uuidv4(), sender, text, timestamp: Date.now() }];
          }
      });
  };

  const playTTS = (text: string) => {
    if (!synthRef.current || mode === InterviewMode.VOICE) return;
    synthRef.current.cancel();
    const utterance = new SpeechSynthesisUtterance(text.replace(/[*#`_]/g, ''));
    const voices = synthRef.current.getVoices();
    const preferred = voices.find(v => v.name.includes('Google US English') || v.lang === 'en-US');
    if (preferred) utterance.voice = preferred;
    synthRef.current.speak(utterance);
  };

  // --- Voice Logic ---
  const stopAudioPlayback = () => {
      // Stop Web Audio API sources (Live API)
      audioSourcesRef.current.forEach(source => { try { source.stop(); } catch (e) {} });
      audioSourcesRef.current = [];

      // Stop Browser TTS
      if (synthRef.current) {
          synthRef.current.cancel();
      }
  };

  const handleTextSubmit = async (e?: React.FormEvent, overrideText?: string) => {
    e?.preventDefault();
    const textToSend = overrideText || inputValue;
    if (!textToSend.trim() && !pendingAttachment) return;

    const attachment = pendingAttachment;
    setPendingAttachment(null);
    if (!overrideText) setInputValue('');

    addMessage(Sender.USER, textToSend, undefined, undefined, undefined, attachment || undefined);
    if (tokenMissing) return;

    if (textToSend.toLowerCase() === '/code') {
        setActiveTab('code');
        addMessage(Sender.SYSTEM, "Switched to Workspace");
        return;
    }

    setIsLoading(true);

    const history = messages.slice(-6).filter(m => !m.imageData).map(m => `${m.sender}: ${m.text}`).join('\n');
    let promptToSend = textToSend;
    let imageContext: { mimeType: string; data: string } | undefined;

    if (attachment) {
      if (attachment.type === 'image') {
        imageContext = { mimeType: attachment.mimeType, data: attachment.data };
        promptToSend += `\n[User attached an image]`;
      } else {
        promptToSend += `\n\n[FILE: ${attachment.fileName}]\n${attachment.data}`;
      }
    }

    try {
        const response = await generateInterviewQuestion(
            history + `\nUSER: ${promptToSend}`,
            persona,
            false,
            resumeData,
            imageContext
        );

        setIsLoading(false);
        const msgId = addMessage(Sender.AI, response.text, response.grounding);
        playTTS(response.text);

        if (response.isCodingChallenge) {
          setActiveTab('code');
          addMessage(Sender.SYSTEM, "Coding Challenge Started - Workspace Active");
        }

        if (response.imagePrompt) {
            generateImage(response.imagePrompt)
                .then(url => setMessages(prev => prev.map(m => m.id === msgId ? { ...m, imageData: url } : m)))
                .catch(console.error);
        }
    } catch (e: any) {
        setIsLoading(false);
        addMessage(Sender.SYSTEM, `Error: ${e.message}`);
    }
  };

  const handleCodeReviewRequest = async (code: string, language: string) => {
    setActiveTab('chat');
    addMessage(Sender.USER, `Submitted ${language} solution for review.`);
    setIsLoading(true);
    addMessage(Sender.SYSTEM, "Analyzing Solution...");
    try {
        const feedback = await reviewCodeWithAI(language, code);
        setIsLoading(false);
        addMessage(Sender.AI, feedback);
        playTTS(feedback);
    } catch (e: any) {
        setIsLoading(false);
        addMessage(Sender.SYSTEM, `Review Error: ${e.message}`);
    }
  };

  const toggleVoiceMode = async () => {
    if (mode === InterviewMode.VOICE) {
        setMode(InterviewMode.TEXT);
        setIsLiveConnected(false);
        if (liveSessionRef.current) { liveSessionRef.current.disconnect(); liveSessionRef.current = null; }
        if (processorRef.current) { processorRef.current.disconnect(); processorRef.current = null; }
        if (sourceRef.current) { sourceRef.current.disconnect(); sourceRef.current = null; }
        if (mediaStreamRef.current) { mediaStreamRef.current.getTracks().forEach(track => track.stop()); mediaStreamRef.current = null; }
        stopAudioPlayback();
        if (audioContextRef.current) { await audioContextRef.current.close(); audioContextRef.current = null; }
    } else {
        try {
            setMode(InterviewMode.VOICE);
            currentTurnTextRef.current = "";
            const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
            const ctx = new AudioContextClass({ sampleRate: 24000 });
            audioContextRef.current = ctx;
            nextStartTimeRef.current = ctx.currentTime;

            const stream = await navigator.mediaDevices.getUserMedia({ audio: { channelCount: 1 } });
            mediaStreamRef.current = stream;

            const session = await connectToLiveSession({
                persona,
                onOpen: () => setIsLiveConnected(true),
                onAudioData: (base64) => {
                    if (!audioContextRef.current) return;
                    try {
                        const buffer = decodeAudioData(base64, audioContextRef.current, 24000);
                        const source = audioContextRef.current.createBufferSource();
                        source.buffer = buffer;
                        source.connect(audioContextRef.current.destination);
                        const now = audioContextRef.current.currentTime;
                        const startTime = Math.max(now, nextStartTimeRef.current);
                        source.start(startTime);
                        nextStartTimeRef.current = startTime + buffer.duration;
                        source.onended = () => { const idx = audioSourcesRef.current.indexOf(source); if (idx > -1) audioSourcesRef.current.splice(idx, 1); };
                        audioSourcesRef.current.push(source);
                    } catch (e) { console.error(e); }
                },
                onTranscript: (text, isUser, isFinal) => {
                    if (isUser) updateLastMessage(text, Sender.USER);
                    else {
                        currentTurnTextRef.current += text;
                        updateLastMessage(currentTurnTextRef.current, Sender.AI);
                        if (isFinal) currentTurnTextRef.current = "";
                    }
                },
                onInterrupted: () => {
                    stopAudioPlayback();
                    nextStartTimeRef.current = audioContextRef.current?.currentTime || 0;
                    currentTurnTextRef.current = "";
                },
                onClose: () => setIsLiveConnected(false),
                onError: (err) => { console.error(err); toggleVoiceMode(); }
            });

            liveSessionRef.current = session;
            const source = ctx.createMediaStreamSource(stream);
            sourceRef.current = source;
            const processor = ctx.createScriptProcessor(4096, 1, 1);
            processorRef.current = processor;
            processor.onaudioprocess = (e) => {
                if (!liveSessionRef.current) return;
                const inputData = e.inputBuffer.getChannelData(0);
                session.sendAudioChunk(downsampleBuffer(inputData, ctx.sampleRate, 16000));
            };
            source.connect(processor);
            processor.connect(ctx.destination);
        } catch (e) { setMode(InterviewMode.TEXT); }
    }
  };

  const extractTextFromPdf = async (file: File): Promise<string> => {
    try {
        const arrayBuffer = await file.arrayBuffer();
        const pdf = await (pdfjsLib as any).getDocument({ data: arrayBuffer }).promise;
        let fullText = '';
        for (let i = 1; i <= pdf.numPages; i++) {
            const page = await pdf.getPage(i);
            const textContent = await page.getTextContent();
            const pageText = textContent.items.map((item: any) => item.str).join(' ');
            fullText += pageText + '\n';
        }
        return fullText || "Empty PDF";
    } catch (e) {
        console.error("PDF Parse Error", e);
        return "Error parsing PDF. Please upload plain text.";
    }
  };

  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    try {
        let attachment: Attachment;
        if (file.type.startsWith('image/')) {
            const dataUrl = await new Promise<string>((resolve) => { const r = new FileReader(); r.onload = () => resolve(r.result as string); r.readAsDataURL(file); });
            attachment = { type: 'image', mimeType: file.type, data: dataUrl, fileName: file.name };
        } else if (file.type === 'application/pdf') {
            const text = await extractTextFromPdf(file);
            attachment = { type: 'file', mimeType: 'text/plain', data: text, fileName: file.name };
            if (!resumeData && (text.includes("Experience") || text.includes("Education"))) {
                setResumeData({ data: text, mimeType: 'text/plain' });
                addMessage(Sender.SYSTEM, "Resume Context Loaded");
            }
        } else {
            const text = await new Promise<string>((resolve) => { const r = new FileReader(); r.onload = () => resolve(r.result as string); r.readAsText(file); });
            attachment = { type: 'file', mimeType: file.type, data: text, fileName: file.name };
            if (!resumeData && (text.includes("Experience") || text.includes("Education"))) {
                setResumeData({ data: text, mimeType: 'text/plain' });
                addMessage(Sender.SYSTEM, "Resume Context Loaded");
            }
        }
        setPendingAttachment(attachment);
    } catch (err: any) { addMessage(Sender.SYSTEM, "Upload Failed"); }
    finally { if (fileInputRef.current) fileInputRef.current.value = ''; }
  };

  return (
    <div className="h-[100dvh] bg-[#121212] text-[#E3E3E3] flex flex-col overflow-hidden font-sans">

      {/* 1. App Bar (Material Style) */}
      <header className="bg-[#1E1E1E] shadow-md px-4 py-3 flex items-center justify-between shrink-0 z-20 material-elevation-2 relative min-h-[64px]">
         {mode === InterviewMode.VOICE ? (
             <div className="flex items-center justify-between w-full animate-slide-up">
                <div className="flex items-center gap-3">
                     <div className="w-10 h-10 rounded-full bg-red-500/20 flex items-center justify-center animate-pulse">
                        <span className="material-symbols-rounded text-red-500 text-[24px]">mic</span>
                     </div>
                     <div className="flex flex-col">
                        <h1 className="text-[16px] font-bold tracking-tight text-white leading-tight">Live Interview</h1>
                        <span className="text-[10px] text-red-400 font-medium tracking-wide uppercase">{isLiveConnected ? 'Listening' : 'Connecting...'}</span>
                     </div>
                </div>

                <button 
                    onClick={toggleVoiceMode}
                    className="bg-red-600/10 hover:bg-red-600/20 text-red-500 border border-red-600/50 px-4 py-2 rounded-full text-xs font-bold flex items-center gap-2 transition-all active:scale-95"
                >
                    <span className="material-symbols-rounded text-[18px]">call_end</span>
                    <span>END</span>
                </button>
             </div>
         ) : (
             <>
                 <div className="flex items-center gap-3">
                     <div className="bg-gradient-to-br from-blue-500 to-purple-600 w-8 h-8 rounded-lg flex items-center justify-center shadow-lg">
                        <span className="material-symbols-rounded text-white text-[20px]">code_blocks</span>
                     </div>
                     <div>
                        <h1 className="text-[16px] font-bold tracking-tight text-white leading-tight">Nexus AI</h1>
                        <div className="flex items-center gap-1.5">
                           <span className="w-1.5 h-1.5 rounded-full bg-green-500"></span>
                           <span className="text-[10px] text-gray-400 font-medium">ONLINE</span>
                        </div>
                     </div>
                 </div>

                 <div className="flex items-center gap-2">
                    {resumeData && <span className="material-symbols-rounded text-green-400 text-[20px]" title="Resume Loaded">description</span>}

                    <button 
                        onClick={() => setPersona(persona === Persona.INTERVIEWER ? Persona.TUTOR : Persona.INTERVIEWER)}
                        className="bg-[#2C2C2C] text-[10px] font-bold px-3 py-1.5 rounded-full border border-[#3C3C3C] text-gray-300 active:bg-[#3C3C3C] transition-colors"
                    >
                        {persona} MODE
                    </button>
                 </div>
             </>
         )}
      </header>

      {/* 2. Body Area */}
      <div className="flex-1 relative overflow-hidden">

        {/* Chat Screen */}
        <div className={`absolute inset-0 flex flex-col transition-transform duration-300 ${activeTab === 'chat' ? 'translate-x-0' : '-translate-x-full'}`}>
           <div className={`flex-1 overflow-y-auto p-4 space-y-4 pb-24 bg-[#121212]`}>
                {messages.length === 0 && (
                    <div className="flex flex-col items-center justify-center h-full text-gray-600 gap-4 opacity-50">
                        <span className="material-symbols-rounded text-6xl">forum</span>
                        <p className="text-sm font-medium">Start your interview session</p>
                    </div>
                )}
                {messages.map((msg) => (
                    <TerminalMessage key={msg.id} message={msg} onPlayAudio={playTTS} />
                ))}
                {isLoading && (
                    <div className="flex justify-start px-2 py-2">
                        <div className="bg-[#2C2C2C] px-4 py-2 rounded-full rounded-tl-sm flex gap-1 items-center">
                            <div className="w-1.5 h-1.5 bg-gray-400 rounded-full typing-dot"></div>
                            <div className="w-1.5 h-1.5 bg-gray-400 rounded-full typing-dot"></div>
                            <div className="w-1.5 h-1.5 bg-gray-400 rounded-full typing-dot"></div>
                        </div>
                    </div>
                )}
                <div ref={messagesEndRef} className="h-4" />
           </div>
        </div>

        {/* Code Screen */}
        <div className={`absolute inset-0 bg-[#0d1117] transition-transform duration-300 ${activeTab === 'code' ? 'translate-x-0' : 'translate-x-full'}`}>
           <CodeEditor onReviewRequest={handleCodeReviewRequest} />
        </div>
      </div>

      {/* 3. Input Area (Always visible even in Voice Mode, allowing text/coding) */}
      <div className={`bg-[#1E1E1E] p-3 border-t border-[#2C2C2C] transition-transform duration-300 ${activeTab === 'chat' ? 'translate-y-0' : 'translate-y-full absolute bottom-0 w-full'}`}>
          {pendingAttachment && (
             <div className="mx-2 mb-2 p-2 bg-[#2C2C2C] rounded-lg flex items-center justify-between border border-[#3C3C3C]">
                 <div className="flex items-center gap-2 overflow-hidden">
                     <span className="material-symbols-rounded text-blue-400 text-sm">attachment</span>
                     <span className="text-xs text-gray-300 truncate">{pendingAttachment.fileName}</span>
                 </div>
                 <button onClick={() => setPendingAttachment(null)} className="text-gray-500 hover:text-red-400">
                     <span className="material-symbols-rounded text-sm">close</span>
                 </button>
             </div>
          )}

          <div className="flex items-center gap-2">
             <button onClick={() => fileInputRef.current?.click()} className="p-3 text-gray-400 hover:text-white rounded-full hover:bg-[#2C2C2C] transition-colors flex-shrink-0">
                 <span className="material-symbols-rounded">attach_file</span>
             </button>

             <button 
                onClick={stopAudioPlayback}
                className="p-3 text-red-400 hover:text-red-300 rounded-full hover:bg-[#2C2C2C] transition-colors flex-shrink-0"
                title="Stop Audio"
             >
                 <span className="material-symbols-rounded">stop_circle</span>
             </button>

             <input type="file" ref={fileInputRef} className="hidden" onChange={handleFileSelect} accept="image/*,.pdf,.txt,.js,.ts,.py" />

             <form onSubmit={(e) => handleTextSubmit(e)} className="flex-1 bg-[#2C2C2C] rounded-3xl border border-[#3C3C3C] focus-within:border-gray-500 transition-colors flex items-center px-4 py-2 min-h-[48px]">
                 <input 
                    type="text" 
                    value={inputValue}
                    onChange={(e) => setInputValue(e.target.value)}
                    placeholder="Message..."
                    className="bg-transparent border-none outline-none text-white w-full placeholder-gray-500 text-[15px]"
                    disabled={isLoading}
                 />
             </form>

             <button 
                onClick={(e) => inputValue.trim() ? handleTextSubmit(e, inputValue) : toggleVoiceMode()}
                className={`p-3 rounded-full shadow-lg transition-transform active:scale-95 flex items-center justify-center flex-shrink-0 ${inputValue.trim() ? 'bg-blue-600 text-white' : 'bg-[#2C2C2C] text-white border border-[#3C3C3C]'}`}
             >
                 <span className="material-symbols-rounded">
                    {inputValue.trim() ? 'send' : 'mic'}
                 </span>
             </button>
          </div>
      </div>

      {/* 4. Bottom Navigation Bar */}
      <nav className="bg-[#1E1E1E] border-t border-[#2C2C2C] pb-safe">
         <div className="flex justify-around items-center h-16">
             <button 
               onClick={() => setActiveTab('chat')} 
               className={`flex flex-col items-center gap-1 w-full h-full justify-center ${activeTab === 'chat' ? 'text-blue-400' : 'text-gray-500'}`}
             >
                <span className={`material-symbols-rounded transition-transform ${activeTab === 'chat' ? 'scale-110 fill-current' : ''}`}>chat_bubble</span>
                <span className="text-[10px] font-medium">Interview</span>
             </button>

             <button 
               onClick={() => setActiveTab('code')}
               className={`flex flex-col items-center gap-1 w-full h-full justify-center ${activeTab === 'code' ? 'text-blue-400' : 'text-gray-500'}`}
             >
                <span className={`material-symbols-rounded transition-transform ${activeTab === 'code' ? 'scale-110 fill-current' : ''}`}>terminal</span>
                <span className="text-[10px] font-medium">Workspace</span>
             </button>
         </div>
      </nav>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type, LiveServerMessage, Modality } from "@google/genai";
import { HfInference } from "@huggingface/inference";
import OpenAI from "openai";
import { GroundingChunk, Persona } from "../types";
import { createPcmBlob } from "../utils/audioUtils";

// Initialize Gemini Client
const apiKey = process.env.API_KEY || "missing_api_key";
const ai = new GoogleGenAI({ apiKey });

// Initialize Hugging Face Inference (For Images)
const hf = new HfInference(process.env.HF_TOKEN || "missing_hf_token");

// Initialize OpenAI Client for HF Router (Fallback - DeepSeek)
const hfRouter = new OpenAI({
  baseURL: "https://router.huggingface.co/v1",
  apiKey: process.env.HF_TOKEN || "missing_hf_token",
  dangerouslyAllowBrowser: true
});

const DEEPSEEK_MODEL = "deepseek-ai/DeepSeek-V3.2";

// --- Tools & Types ---

export interface ResumeData {
  data: string;
  mimeType: string;
}

// --- DeepSeek Integration (OpenAI Compatibility Layer) ---

const generateWithDeepSeek = async (
  systemPrompt: string, 
  userPrompt: string
): Promise<{ text: string, imagePrompt?: string, isCodingChallenge?: boolean } | null> => {
    if (process.env.HF_TOKEN === "missing_hf_token") return null;

    try {
        console.log(`Attempting generation with ${DEEPSEEK_MODEL} via HF Router...`);

        const jsonInstruction = `
        RESPONSE FORMAT: JSON ONLY.
        {
            "content": "string (the interview question)",
            "visual_description": "string | null",
            "is_coding_challenge": "boolean"
        }`;

        const completion = await hfRouter.chat.completions.create({
            model: DEEPSEEK_MODEL,
            messages: [
                { role: "system", content: systemPrompt + jsonInstruction },
                { role: "user", content: userPrompt }
            ],
            max_tokens: 1024,
            temperature: 0.7,
            stream: false
        });

        const rawContent = completion.choices[0]?.message?.content || "{}";
        const cleanContent = rawContent.replace(/```json/g, "").replace(/```/g, "").trim();

        let parsed;
        try {
            parsed = JSON.parse(cleanContent);
        } catch (parseErr) {
            console.warn("DeepSeek JSON Parse Failed");
            return { text: rawContent, isCodingChallenge: false };
        }

        return {
            text: parsed.content || rawContent,
            imagePrompt: parsed.visual_description,
            isCodingChallenge: !!parsed.is_coding_challenge
        };
    } catch (e: any) {
        console.warn(`DeepSeek failed:`, e.message);
        return null;
    }
};

// --- Text & Reasoning (Standard API) ---

export const generateInterviewQuestion = async (
  history: string, 
  persona: Persona,
  useThinking: boolean = false,
  resume?: ResumeData,
  imageContext?: { mimeType: string; data: string }
): Promise<{ text: string, imagePrompt?: string, grounding?: GroundingChunk[], isCodingChallenge?: boolean }> => {

  if (apiKey === "missing_api_key") {
      return { text: "Error: API Key is missing. Please configure it in your deployment settings." };
  }

  const baseInstruction = persona === Persona.TUTOR 
    ? "Role: Friendly AI Coding Tutor. Be encouraging."
    : `Role: Strict Technical Interviewer. 
1. Ask one distinct question at a time.
2. Prioritize resume questions.
3. For coding problems: Title, Description, Examples, Constraints.
4. No full solutions.`;

  let prompt = history;
  if (resume) {
      prompt = `RESUME:\n${resume.data}\n\n${prompt}`;
  }

  let systemInstruction = `${baseInstruction}

  Output MUST be JSON:
  {
    "content": "string", 
    "visual_description": "string|null", 
    "is_coding_challenge": boolean
  }`;

  try {
    const model = useThinking ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';
    const config: any = {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
            type: Type.OBJECT,
            properties: {
                content: { type: Type.STRING },
                visual_description: { type: Type.STRING, nullable: true },
                is_coding_challenge: { type: Type.BOOLEAN }
            },
            required: ["content", "is_coding_challenge"]
        }
    };

    if (useThinking) {
        config.thinkingConfig = { thinkingBudget: 1024 };
    }

    let contents: any = prompt;
    if (imageContext) {
        contents = {
            parts: [
                { text: prompt },
                {
                    inlineData: {
                        mimeType: imageContext.mimeType,
                        data: imageContext.data.includes(',') ? imageContext.data.split(',')[1] : imageContext.data
                    }
                }
            ]
        };
    }

    const response = await ai.models.generateContent({
      model,
      contents,
      config
    });

    const grounding: GroundingChunk[] = [];
    if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
        response.candidates[0].groundingMetadata.groundingChunks.forEach((chunk: any) => {
            if (chunk.web) grounding.push({ web: chunk.web });
        });
    }

    let parsedResponse;
    try {
        parsedResponse = JSON.parse(response.text || "{}");
    } catch (e) {
        return { text: response.text || "Error parsing response." };
    }

    return {
      text: parsedResponse.content || "Error generating content.",
      imagePrompt: parsedResponse.visual_description,
      grounding,
      isCodingChallenge: parsedResponse.is_coding_challenge
    };
  } catch (error: any) {
    console.error("Gemini API Error:", error);

    const deepSeekFallback = await generateWithDeepSeek(baseInstruction, prompt);
    if (deepSeekFallback) {
          return {
              ...deepSeekFallback,
              text: deepSeekFallback.text
          };
    }

    return { text: `API Error: ${error.message || "Unknown error"}` };
  }
};

export const fastAck = async (input: string): Promise<string> => {
  if (apiKey === "missing_api_key") return "...";
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Ack in 3 words: ${input}`,
      config: { maxOutputTokens: 20 }
    });
    return response.text || "Acknowledged.";
  } catch (e) {
    return "...";
  }
};

// --- Live API (Real-time Audio) ---

export interface LiveSessionConfig {
  onOpen: () => void;
  onAudioData: (base64: string) => void;
  onTranscript: (text: string, isUser: boolean, isFinal: boolean) => void;
  onClose: () => void;
  onError: (err: any) => void;
  onInterrupted: () => void;
  persona: Persona;
}

export const connectToLiveSession = async (config: LiveSessionConfig) => {
  if (apiKey === "missing_api_key") {
      config.onError(new Error("API Key missing"));
      return { sendAudioChunk: () => {}, disconnect: () => {} };
  }

  const model = 'gemini-2.5-flash-native-audio-preview-12-2025';

  const systemInstruction = config.persona === Persona.TUTOR
    ? "Role: Patient Coding Tutor. Concise answers."
    : "Role: Strict Interviewer. One short question at a time. Interrupt if needed.";

  const sessionPromise = ai.live.connect({
    model,
    callbacks: {
      onopen: () => {
        config.onOpen();
      },
      onmessage: (message: LiveServerMessage) => {
        // Handle Audio Output
        const audioData = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
        if (audioData) {
          config.onAudioData(audioData);
        }

        // Handle Transcripts
        if (message.serverContent?.outputTranscription) {
            config.onTranscript(message.serverContent.outputTranscription.text || "", false, !!message.serverContent.turnComplete);
        } else if (message.serverContent?.inputTranscription) {
            config.onTranscript(message.serverContent.inputTranscription.text || "", true, true);
        }

        // Handle Interruption
        if (message.serverContent?.interrupted) {
            config.onInterrupted();
        }
      },
      onclose: () => {
        config.onClose();
      },
      onerror: (err) => {
        config.onError(err);
      }
    },
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
      },
      inputAudioTranscription: {}, 
      outputAudioTranscription: {}, 
      systemInstruction: { parts: [{ text: systemInstruction }] },
    }
  });

  return {
    sendAudioChunk: (data: Float32Array) => {
      const blob = createPcmBlob(data);
      sessionPromise.then(session => {
        session.sendRealtimeInput({ media: blob });
      });
    },
    disconnect: () => {
      sessionPromise.then(session => session.close());
    }
  };
};

// --- Image Generation ---

export const generateImage = async (prompt: string): Promise<string> => {
  if (apiKey === "missing_api_key") throw new Error("API Key missing");

  // 1. Primary: Gemini 2.5 Flash Image (Fast, Native)
  try {
      console.log("Generating with Gemini 2.5 Flash Image...");
      const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash-image',
          contents: { parts: [{ text: prompt }] },
          config: { imageConfig: { aspectRatio: "16:9" } }
      });
      for (const part of response.candidates?.[0]?.content?.parts || []) {
          if (part.inlineData && part.inlineData.data) {
              return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
          }
      }
  } catch (error: any) {
      console.warn("Gemini 2.5 Flash Image Error:", error.message);
  }

  // 2. Secondary: Imagen 3 (High Quality)
  try {
      const response = await ai.models.generateImages({
        model: 'imagen-3.0-generate-001',
        prompt: prompt,
        config: {
          numberOfImages: 1,
          outputMimeType: 'image/jpeg',
          aspectRatio: '16:9',
        },
      });
      const b64 = response.generatedImages?.[0]?.image?.imageBytes;
      if (b64) return `data:image/jpeg;base64,${b64}`;
  } catch(e: any) {
      console.warn("Imagen 3.0 Error:", e.message);
  }

  // 3. Last Resort: Hugging Face
  const hfModels = ["runwayml/stable-diffusion-v1-5"];
  for (const model of hfModels) {
    try {
        if (process.env.HF_TOKEN === "missing_hf_token") continue;
        const blob = await hf.textToImage({
          model: model,
          inputs: prompt,
          parameters: { negative_prompt: "blurry" }
        });
        return await new Promise((resolve, reject) => {
          const reader = new FileReader();
          reader.onloadend = () => resolve(reader.result as string);
          reader.onerror = reject;
          reader.readAsDataURL(blob as unknown as Blob);
        });
    } catch (error: any) {
        console.warn(`HF Error (${model}):`, error.message);
    }
  }
  throw new Error("Failed to generate visualization.");
};

// --- Code Execution & Review ---

export const runCodeWithAI = async (language: string, code: string): Promise<string> => {
  if (apiKey === "missing_api_key") return "Error: API Key missing.";
  try {
    const prompt = `Act as a compiler for ${language}. Execute: ${code}`;
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt
    });
    let text = response.text || "";
    text = text.replace(/^```[\w]*\n?/, '').replace(/\n?```$/, '');
    return text.trim() || "[No Output]";
  } catch (error: any) {
    return `Error: ${error.message}`;
  }
};

export const reviewCodeWithAI = async (language: string, code: string): Promise<string> => {
  if (apiKey === "missing_api_key") return "Error: API Key missing.";
  const prompt = `Review this ${language} code:\n${code}`;

  try {
    const deepSeekReview = await generateWithDeepSeek(
        "Expert Reviewer. Concise.", 
        prompt + "\nJSON Output: { content: 'string' }"
    );
    if (deepSeekReview) return deepSeekReview.text;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt
    });
    return response.text || "No feedback.";
  } catch (error: any) {
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt
        });
        return response.text || "No feedback.";
    } catch (fallbackError: any) {
        return `Error: ${fallbackError.message}`;
    }
  }
};

// --- Maps Grounding ---
export const getGeographicContext = async (query: string, lat?: number, lng?: number): Promise<{ text: string, grounding: GroundingChunk[] }> => {
  if (apiKey === "missing_api_key") return { text: "API Key missing.", grounding: [] };
  try {
      const config: any = { tools: [{ googleMaps: {} }] };
      if (lat && lng) {
          config.toolConfig = { retrievalConfig: { latLng: { latitude: lat, longitude: lng } } };
      }
      const response = await ai.models.generateContent({
          model: 'gemini-2.5-flash', 
          contents: query,
          config
      });
      const grounding: GroundingChunk[] = [];
      if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
           response.candidates[0].groundingMetadata.groundingChunks.forEach((chunk: any) => {
               if (chunk.maps) grounding.push({ maps: chunk.maps });
               if (chunk.web) grounding.push({ web: chunk.web });
           });
      }
      return { text: response.text || "No location info.", grounding };
  } catch (e) {
      return { text: "Geographic context currently unavailable.", grounding: [] };
  }
};

// --- Live API ---
export const getLiveSession = () => {
    return ai.live; 
};

import React, { useState, useEffect, useRef } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  generateInterviewQuestion, 
  generateImage,
  connectToLiveSession,
  reviewCodeWithAI,
  ResumeData
} from './services/geminiService';
import { decodeAudioData, downsampleBuffer } from './utils/audioUtils';
import { TerminalMessage } from './components/TerminalMessage';
import { CodeEditor } from './components/CodeEditor';
import { Message, Sender, InterviewMode, Persona, Attachment } from './types';

const App: React.FC = () => {
  // Navigation State
  const [activeTab, setActiveTab] = useState<'chat' | 'code'>('chat');

  // App Logic State
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [mode, setMode] = useState<InterviewMode>(InterviewMode.TEXT);
  const [persona, setPersona] = useState<Persona>(Persona.INTERVIEWER);
  const [isLiveConnected, setIsLiveConnected] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [tokenMissing, setTokenMissing] = useState(false);

  // Data State
  const [resumeData, setResumeData] = useState<ResumeData | undefined>(undefined);
  const [pendingAttachment, setPendingAttachment] = useState<Attachment | null>(null);

  // Refs
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const synthRef = useRef<SpeechSynthesis>(window.speechSynthesis);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Audio Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const sourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const liveSessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef<number>(0);
  const audioSourcesRef = useRef<AudioBufferSourceNode[]>([]);
  const currentTurnTextRef = useRef<string>("");

  // Init
  useEffect(() => {
    const key = process.env.API_KEY;
    if (!key || key.trim() === '') {
        setTokenMissing(true);
        addMessage(Sender.SYSTEM, "Configuration Error: API_KEY is missing.");
    } else {
        // Immediate welcome message for perceived speed
        addMessage(Sender.AI, "Welcome. I am your Nexus AI Assistant. Ready for your technical assessment.");
    }

    return () => { if (audioContextRef.current) audioContextRef.current.close(); };
  }, []);

  // Auto-scroll
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isLoading, pendingAttachment, activeTab]);

  const addMessage = (sender: Sender, text: string, grounding?: any[], isThinking = false, imageData?: string, attachment?: Attachment) => {
    const id = uuidv4();
    setMessages(prev => [...prev, {
      id,
      sender,
      text,
      timestamp: Date.now(),
      grounding,
      isThinking,
      imageData,
      attachment
    }]);
    return id;
  };

  const updateLastMessage = (text: string, sender: Sender) => {
      setMessages(prev => {
          const last = prev[prev.length - 1];
          if (last && last.sender === sender) {
              return [...prev.slice(0, -1), { ...last, text: text }];
          } else {
              return [...prev, { id: uuidv4(), sender, text, timestamp: Date.now() }];
          }
      });
  };

  const playTTS = (text: string) => {
    if (!synthRef.current || mode === InterviewMode.VOICE) return;
    synthRef.current.cancel();
    const utterance = new SpeechSynthesisUtterance(text.replace(/[*#`_]/g, ''));
    const voices = synthRef.current.getVoices();
    const preferred = voices.find(v => v.name.includes('Google US English') || v.lang === 'en-US');
    if (preferred) utterance.voice = preferred;
    synthRef.current.speak(utterance);
  };

  // --- Voice Logic ---
  const stopAudioPlayback = () => {
      // Stop Web Audio API sources (Live API)
      audioSourcesRef.current.forEach(source => { try { source.stop(); } catch (e) {} });
      audioSourcesRef.current = [];

      // Stop Browser TTS
      if (synthRef.current) {
          synthRef.current.cancel();
      }
  };

  const handleTextSubmit = async (e?: React.FormEvent, overrideText?: string) => {
    e?.preventDefault();
    const textToSend = overrideText || inputValue;
    if (!textToSend.trim() && !pendingAttachment) return;

    const attachment = pendingAttachment;
    setPendingAttachment(null);
    if (!overrideText) setInputValue('');

    addMessage(Sender.USER, textToSend, undefined, undefined, undefined, attachment || undefined);
    if (tokenMissing) return;

    if (textToSend.toLowerCase() === '/code') {
        setActiveTab('code');
        addMessage(Sender.SYSTEM, "Switched to Workspace");
        return;
    }

    setIsLoading(true);

    const history = messages.slice(-6).filter(m => !m.imageData).map(m => `${m.sender}: ${m.text}`).join('\n');
    let promptToSend = textToSend;
    let imageContext: { mimeType: string; data: string } | undefined;

    if (attachment) {
      if (attachment.type === 'image') {
        imageContext = { mimeType: attachment.mimeType, data: attachment.data };
        promptToSend += `\n[User attached an image]`;
      } else {
        promptToSend += `\n\n[FILE: ${attachment.fileName}]\n${attachment.data}`;
      }
    }

    try {
        const response = await generateInterviewQuestion(
            history + `\nUSER: ${promptToSend}`,
            persona,
            false,
            resumeData,
            imageContext
        );

        setIsLoading(false);
        const msgId = addMessage(Sender.AI, response.text, response.grounding);
        playTTS(response.text);

        if (response.isCodingChallenge) {
          setActiveTab('code');
          addMessage(Sender.SYSTEM, "Coding Challenge Started - Workspace Active");
        }

        if (response.imagePrompt) {
            generateImage(response.imagePrompt)
                .then(url => setMessages(prev => prev.map(m => m.id === msgId ? { ...m, imageData: url } : m)))
                .catch(console.error);
        }
    } catch (e: any) {
        setIsLoading(false);
        addMessage(Sender.SYSTEM, `Error: ${e.message}`);
    }
  };

  const handleCodeReviewRequest = async (code: string, language: string) => {
    setActiveTab('chat');
    addMessage(Sender.USER, `Submitted ${language} solution for review.`);
    setIsLoading(true);
    addMessage(Sender.SYSTEM, "Analyzing Solution...");
    try {
        const feedback = await reviewCodeWithAI(language, code);
        setIsLoading(false);
        addMessage(Sender.AI, feedback);
        playTTS(feedback);
    } catch (e: any) {
        setIsLoading(false);
        addMessage(Sender.SYSTEM, `Review Error: ${e.message}`);
    }
  };

  const toggleVoiceMode = async () => {
    if (mode === InterviewMode.VOICE) {
        setMode(InterviewMode.TEXT);
        setIsLiveConnected(false);
        if (liveSessionRef.current) { liveSessionRef.current.disconnect(); liveSessionRef.current = null; }
        if (processorRef.current) { processorRef.current.disconnect(); processorRef.current = null; }
        if (sourceRef.current) { sourceRef.current.disconnect(); sourceRef.current = null; }
        if (mediaStreamRef.current) { mediaStreamRef.current.getTracks().forEach(track => track.stop()); mediaStreamRef.current = null; }
        stopAudioPlayback();
        if (audioContextRef.current) { await audioContextRef.current.close(); audioContextRef.current = null; }
    } else {
        try {
            setMode(InterviewMode.VOICE);
            currentTurnTextRef.current = "";
            const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
            const ctx = new AudioContextClass({ sampleRate: 24000 });
            audioContextRef.current = ctx;
            nextStartTimeRef.current = ctx.currentTime;

            const stream = await navigator.mediaDevices.getUserMedia({ audio: { channelCount: 1 } });
            mediaStreamRef.current = stream;

            const session = await connectToLiveSession({
                persona,
                onOpen: () => setIsLiveConnected(true),
                onAudioData: (base64) => {
                    if (!audioContextRef.current) return;
                    try {
                        const buffer = decodeAudioData(base64, audioContextRef.current, 24000);
                        const source = audioContextRef.current.createBufferSource();
                        source.buffer = buffer;
                        source.connect(audioContextRef.current.destination);
                        const now = audioContextRef.current.currentTime;
                        const startTime = Math.max(now, nextStartTimeRef.current);
                        source.start(startTime);
                        nextStartTimeRef.current = startTime + buffer.duration;
                        source.onended = () => { const idx = audioSourcesRef.current.indexOf(source); if (idx > -1) audioSourcesRef.current.splice(idx, 1); };
                        audioSourcesRef.current.push(source);
                    } catch (e) { console.error(e); }
                },
                onTranscript: (text, isUser, isFinal) => {
                    if (isUser) updateLastMessage(text, Sender.USER);
                    else {
                        currentTurnTextRef.current += text;
                        updateLastMessage(currentTurnTextRef.current, Sender.AI);
                        if (isFinal) currentTurnTextRef.current = "";
                    }
                },
                onInterrupted: () => {
                    stopAudioPlayback();
                    nextStartTimeRef.current = audioContextRef.current?.currentTime || 0;
                    currentTurnTextRef.current = "";
                },
                onClose: () => setIsLiveConnected(false),
                onError: (err) => { console.error(err); toggleVoiceMode(); }
            });

            liveSessionRef.current = session;
            const source = ctx.createMediaStreamSource(stream);
            sourceRef.current = source;
            const processor = ctx.createScriptProcessor(4096, 1, 1);
            processorRef.current = processor;
            processor.onaudioprocess = (e) => {
                if (!liveSessionRef.current) return;
                const inputData = e.inputBuffer.getChannelData(0);
                session.sendAudioChunk(downsampleBuffer(inputData, ctx.sampleRate, 16000));
            };
            source.connect(processor);
            processor.connect(ctx.destination);
        } catch (e) { setMode(InterviewMode.TEXT); }
    }
  };

  const extractTextFromPdf = async (file: File): Promise<string> => {
    try {
        // Dynamic import to avoid loading PDF.js on initial load
        const pdfjsLib = await import('pdfjs-dist');
        const pdfjs = pdfjsLib as any;

        if (!pdfjs.GlobalWorkerOptions.workerSrc) {
            pdfjs.GlobalWorkerOptions.workerSrc = "https://unpkg.com/pdfjs-dist@3.11.174/build/pdf.worker.min.js";
        }

        const arrayBuffer = await file.arrayBuffer();
        const pdf = await pdfjs.getDocument({ data: arrayBuffer }).promise;
        let fullText = '';
        for (let i = 1; i <= pdf.numPages; i++) {
            const page = await pdf.getPage(i);
            const textContent = await page.getTextContent();
            const pageText = textContent.items.map((item: any) => item.str).join(' ');
            fullText += pageText + '\n';
        }
        return fullText || "Empty PDF";
    } catch (e) {
        console.error("PDF Parse Error", e);
        return "Error parsing PDF. Please upload plain text.";
    }
  };

  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    try {
        let attachment: Attachment;
        if (file.type.startsWith('image/')) {
            const dataUrl = await new Promise<string>((resolve) => { const r = new FileReader(); r.onload = () => resolve(r.result as string); r.readAsDataURL(file); });
            attachment = { type: 'image', mimeType: file.type, data: dataUrl, fileName: file.name };
        } else if (file.type === 'application/pdf') {
            const text = await extractTextFromPdf(file);
            attachment = { type: 'file', mimeType: 'text/plain', data: text, fileName: file.name };
            if (!resumeData && (text.includes("Experience") || text.includes("Education"))) {
                setResumeData({ data: text, mimeType: 'text/plain' });
                addMessage(Sender.SYSTEM, "Resume Context Loaded");
            }
        } else {
            const text = await new Promise<string>((resolve) => { const r = new FileReader(); r.onload = () => resolve(r.result as string); r.readAsText(file); });
            attachment = { type: 'file', mimeType: file.type, data: text, fileName: file.name };
            if (!resumeData && (text.includes("Experience") || text.includes("Education"))) {
                setResumeData({ data: text, mimeType: 'text/plain' });
                addMessage(Sender.SYSTEM, "Resume Context Loaded");
            }
        }
        setPendingAttachment(attachment);
    } catch (err: any) { addMessage(Sender.SYSTEM, "Upload Failed"); }
    finally { if (fileInputRef.current) fileInputRef.current.value = ''; }
  };

  return (
    <div className="h-[100dvh] bg-[#121212] text-[#E3E3E3] flex flex-col overflow-hidden font-sans">

      {/* 1. App Bar (Material Style) */}
      <header className="bg-[#1E1E1E] shadow-md px-4 py-3 flex items-center justify-between shrink-0 z-20 material-elevation-2 relative min-h-[64px]">
         {mode === InterviewMode.VOICE ? (
             <div className="flex items-center justify-between w-full animate-slide-up">
                <div className="flex items-center gap-3">
                     <div className="w-10 h-10 rounded-full bg-red-500/20 flex items-center justify-center animate-pulse">
                        <span className="material-symbols-rounded text-red-500 text-[24px]">mic</span>
                     </div>
                     <div className="flex flex-col">
                        <h1 className="text-[16px] font-bold tracking-tight text-white leading-tight">Live Interview</h1>
                        <span className="text-[10px] text-red-400 font-medium tracking-wide uppercase">{isLiveConnected ? 'Listening' : 'Connecting...'}</span>
                     </div>
                </div>

                <button 
                    onClick={toggleVoiceMode}
                    className="bg-red-600/10 hover:bg-red-600/20 text-red-500 border border-red-600/50 px-4 py-2 rounded-full text-xs font-bold flex items-center gap-2 transition-all active:scale-95"
                >
                    <span className="material-symbols-rounded text-[18px]">call_end</span>
                    <span>END</span>
                </button>
             </div>
         ) : (
             <>
                 <div className="flex items-center gap-3">
                     <div className="bg-gradient-to-br from-blue-500 to-purple-600 w-8 h-8 rounded-lg flex items-center justify-center shadow-lg">
                        <span className="material-symbols-rounded text-white text-[20px]">code_blocks</span>
                     </div>
                     <div>
                        <h1 className="text-[16px] font-bold tracking-tight text-white leading-tight">Nexus AI</h1>
                        <div className="flex items-center gap-1.5">
                           <span className="w-1.5 h-1.5 rounded-full bg-green-500"></span>
                           <span className="text-[10px] text-gray-400 font-medium">ONLINE</span>
                        </div>
                     </div>
                 </div>

                 <div className="flex items-center gap-2">
                    {resumeData && <span className="material-symbols-rounded text-green-400 text-[20px]" title="Resume Loaded">description</span>}

                    <button 
                        onClick={() => setPersona(persona === Persona.INTERVIEWER ? Persona.TUTOR : Persona.INTERVIEWER)}
                        className="bg-[#2C2C2C] text-[10px] font-bold px-3 py-1.5 rounded-full border border-[#3C3C3C] text-gray-300 active:bg-[#3C3C3C] transition-colors"
                    >
                        {persona} MODE
                    </button>
                 </div>
             </>
         )}
      </header>

      {/* 2. Body Area */}
      <div className="flex-1 relative overflow-hidden">

        {/* Chat Screen */}
        <div className={`absolute inset-0 flex flex-col transition-transform duration-300 ${activeTab === 'chat' ? 'translate-x-0' : '-translate-x-full'}`}>
           <div className={`flex-1 overflow-y-auto p-4 space-y-4 pb-24 bg-[#121212]`}>
                {messages.length === 0 && (
                    <div className="flex flex-col items-center justify-center h-full text-gray-600 gap-4 opacity-50">
                        <span className="material-symbols-rounded text-6xl">forum</span>
                        <p className="text-sm font-medium">Start your interview session</p>
                    </div>
                )}
                {messages.map((msg) => (
                    <TerminalMessage key={msg.id} message={msg} onPlayAudio={playTTS} />
                ))}
                {isLoading && (
                    <div className="flex justify-start px-2 py-2">
                        <div className="bg-[#2C2C2C] px-4 py-2 rounded-full rounded-tl-sm flex gap-1 items-center">
                            <div className="w-1.5 h-1.5 bg-gray-400 rounded-full typing-dot"></div>
                            <div className="w-1.5 h-1.5 bg-gray-400 rounded-full typing-dot"></div>
                            <div className="w-1.5 h-1.5 bg-gray-400 rounded-full typing-dot"></div>
                        </div>
                    </div>
                )}
                <div ref={messagesEndRef} className="h-4" />
           </div>
        </div>

        {/* Code Screen */}
        <div className={`absolute inset-0 bg-[#0d1117] transition-transform duration-300 ${activeTab === 'code' ? 'translate-x-0' : 'translate-x-full'}`}>
           <CodeEditor onReviewRequest={handleCodeReviewRequest} />
        </div>
      </div>

      {/* 3. Input Area (Always visible even in Voice Mode, allowing text/coding) */}
      <div className={`bg-[#1E1E1E] p-3 border-t border-[#2C2C2C] transition-transform duration-300 ${activeTab === 'chat' ? 'translate-y-0' : 'translate-y-full absolute bottom-0 w-full'}`}>
          {pendingAttachment && (
             <div className="mx-2 mb-2 p-2 bg-[#2C2C2C] rounded-lg flex items-center justify-between border border-[#3C3C3C]">
                 <div className="flex items-center gap-2 overflow-hidden">
                     <span className="material-symbols-rounded text-blue-400 text-sm">attachment</span>
                     <span className="text-xs text-gray-300 truncate">{pendingAttachment.fileName}</span>
                 </div>
                 <button onClick={() => setPendingAttachment(null)} className="text-gray-500 hover:text-red-400">
                     <span className="material-symbols-rounded text-sm">close</span>
                 </button>
             </div>
          )}

          <div className="flex items-center gap-2">
             <button onClick={() => fileInputRef.current?.click()} className="p-3 text-gray-400 hover:text-white rounded-full hover:bg-[#2C2C2C] transition-colors flex-shrink-0">
                 <span className="material-symbols-rounded">attach_file</span>
             </button>

             <button 
                onClick={stopAudioPlayback}
                className="p-3 text-red-400 hover:text-red-300 rounded-full hover:bg-[#2C2C2C] transition-colors flex-shrink-0"
                title="Stop Audio"
             >
                 <span className="material-symbols-rounded">stop_circle</span>
             </button>

             <input type="file" ref={fileInputRef} className="hidden" onChange={handleFileSelect} accept="image/*,.pdf,.txt,.js,.ts,.py" />

             <form onSubmit={(e) => handleTextSubmit(e)} className="flex-1 bg-[#2C2C2C] rounded-3xl border border-[#3C3C3C] focus-within:border-gray-500 transition-colors flex items-center px-4 py-2 min-h-[48px]">
                 <input 
                    type="text" 
                    value={inputValue}
                    onChange={(e) => setInputValue(e.target.value)}
                    placeholder="Message..."
                    className="bg-transparent border-none outline-none text-white w-full placeholder-gray-500 text-[15px]"
                    disabled={isLoading}
                 />
             </form>

             <button 
                onClick={(e) => inputValue.trim() ? handleTextSubmit(e, inputValue) : toggleVoiceMode()}
                className={`p-3 rounded-full shadow-lg transition-transform active:scale-95 flex items-center justify-center flex-shrink-0 ${inputValue.trim() ? 'bg-blue-600 text-white' : 'bg-[#2C2C2C] text-white border border-[#3C3C3C]'}`}
             >
                 <span className="material-symbols-rounded">
                    {inputValue.trim() ? 'send' : 'mic'}
                 </span>
             </button>
          </div>
      </div>

      {/* 4. Bottom Navigation Bar */}
      <nav className="bg-[#1E1E1E] border-t border-[#2C2C2C] pb-safe">
         <div className="flex justify-around items-center h-16">
             <button 
               onClick={() => setActiveTab('chat')} 
               className={`flex flex-col items-center gap-1 w-full h-full justify-center ${activeTab === 'chat' ? 'text-blue-400' : 'text-gray-500'}`}
             >
                <span className={`material-symbols-rounded transition-transform ${activeTab === 'chat' ? 'scale-110 fill-current' : ''}`}>chat_bubble</span>
                <span className="text-[10px] font-medium">Interview</span>
             </button>

             <button 
               onClick={() => setActiveTab('code')}
               className={`flex flex-col items-center gap-1 w-full h-full justify-center ${activeTab === 'code' ? 'text-blue-400' : 'text-gray-500'}`}
             >
                <span className={`material-symbols-rounded transition-transform ${activeTab === 'code' ? 'scale-110 fill-current' : ''}`}>terminal</span>
                <span className="text-[10px] font-medium">Workspace</span>
             </button>
         </div>
      </nav>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  generateInterviewQuestion, 
  generateImage,
  connectToLiveSession,
  reviewCodeWithAI,
  ResumeData
} from './services/geminiService';
import { decodeAudioData, downsampleBuffer } from './utils/audioUtils';
import { TerminalMessage } from './components/TerminalMessage';
import { CodeEditor } from './components/CodeEditor';
import { Message, Sender, InterviewMode, Persona, Attachment } from './types';

const App: React.FC = () => {
  // Navigation State
  const [activeTab, setActiveTab] = useState<'chat' | 'code'>('chat');

  // App Logic State
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [mode, setMode] = useState<InterviewMode>(InterviewMode.TEXT);
  const [persona, setPersona] = useState<Persona>(Persona.INTERVIEWER);
  const [isLiveConnected, setIsLiveConnected] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [tokenMissing, setTokenMissing] = useState(false);

  // Data State
  const [resumeData, setResumeData] = useState<ResumeData | undefined>(undefined);
  const [pendingAttachment, setPendingAttachment] = useState<Attachment | null>(null);

  // Refs
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const synthRef = useRef<SpeechSynthesis>(window.speechSynthesis);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Audio Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const sourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const liveSessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef<number>(0);
  const audioSourcesRef = useRef<AudioBufferSourceNode[]>([]);
  const currentTurnTextRef = useRef<string>("");

  // Init
  useEffect(() => {
    const key = process.env.API_KEY;
    if (!key || key.trim() === '') {
        setTokenMissing(true);
        addMessage(Sender.SYSTEM, "Configuration Error: API_KEY is missing.");
    } else {
        // Immediate welcome message for perceived speed
        addMessage(Sender.AI, "Welcome. I am your Nexus AI Assistant. Ready for your technical assessment.");
    }

    return () => { if (audioContextRef.current) audioContextRef.current.close(); };
  }, []);

  // Auto-scroll
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isLoading, pendingAttachment, activeTab]);

  const addMessage = (sender: Sender, text: string, grounding?: any[], isThinking = false, imageData?: string, attachment?: Attachment) => {
    const id = uuidv4();
    setMessages(prev => [...prev, {
      id,
      sender,
      text,
      timestamp: Date.now(),
      grounding,
      isThinking,
      imageData,
      attachment
    }]);
    return id;
  };

  const updateLastMessage = (text: string, sender: Sender) => {
      setMessages(prev => {
          const last = prev[prev.length - 1];
          if (last && last.sender === sender) {
              return [...prev.slice(0, -1), { ...last, text: text }];
          } else {
              return [...prev, { id: uuidv4(), sender, text, timestamp: Date.now() }];
          }
      });
  };

  const playTTS = (text: string) => {
    if (!synthRef.current || mode === InterviewMode.VOICE) return;
    synthRef.current.cancel();
    const utterance = new SpeechSynthesisUtterance(text.replace(/[*#`_]/g, ''));
    const voices = synthRef.current.getVoices();
    const preferred = voices.find(v => v.name.includes('Google US English') || v.lang === 'en-US');
    if (preferred) utterance.voice = preferred;
    synthRef.current.speak(utterance);
  };

  // --- Voice Logic ---
  const stopAudioPlayback = () => {
      // Stop Web Audio API sources (Live API)
      audioSourcesRef.current.forEach(source => { try { source.stop(); } catch (e) {} });
      audioSourcesRef.current = [];

      // Stop Browser TTS
      if (synthRef.current) {
          synthRef.current.cancel();
      }
  };

  const handleTextSubmit = async (e?: React.FormEvent, overrideText?: string) => {
    e?.preventDefault();
    const textToSend = overrideText || inputValue;
    if (!textToSend.trim() && !pendingAttachment) return;

    const attachment = pendingAttachment;
    setPendingAttachment(null);
    if (!overrideText) setInputValue('');

    addMessage(Sender.USER, textToSend, undefined, undefined, undefined, attachment || undefined);
    if (tokenMissing) return;

    if (textToSend.toLowerCase() === '/code') {
        setActiveTab('code');
        addMessage(Sender.SYSTEM, "Switched to Workspace");
        return;
    }

    setIsLoading(true);

    const history = messages.slice(-6).filter(m => !m.imageData).map(m => `${m.sender}: ${m.text}`).join('\n');
    let promptToSend = textToSend;
    let imageContext: { mimeType: string; data: string } | undefined;

    if (attachment) {
      if (attachment.type === 'image') {
        imageContext = { mimeType: attachment.mimeType, data: attachment.data };
        promptToSend += `\n[User attached an image]`;
      } else {
        promptToSend += `\n\n[FILE: ${attachment.fileName}]\n${attachment.data}`;
      }
    }

    try {
        const response = await generateInterviewQuestion(
            history + `\nUSER: ${promptToSend}`,
            persona,
            false,
            resumeData,
            imageContext
        );

        setIsLoading(false);
        const msgId = addMessage(Sender.AI, response.text, response.grounding);
        playTTS(response.text);

        if (response.isCodingChallenge) {
          setActiveTab('code');
          addMessage(Sender.SYSTEM, "Coding Challenge Started - Workspace Active");
        }

        if (response.imagePrompt) {
            generateImage(response.imagePrompt)
                .then(url => setMessages(prev => prev.map(m => m.id === msgId ? { ...m, imageData: url } : m)))
                .catch(console.error);
        }
    } catch (e: any) {
        setIsLoading(false);
        addMessage(Sender.SYSTEM, `Error: ${e.message}`);
    }
  };

  const handleCodeReviewRequest = async (code: string, language: string) => {
    setActiveTab('chat');
    addMessage(Sender.USER, `Submitted ${language} solution for review.`);
    setIsLoading(true);
    addMessage(Sender.SYSTEM, "Analyzing Solution...");
    try {
        const feedback = await reviewCodeWithAI(language, code);
        setIsLoading(false);
        addMessage(Sender.AI, feedback);
        playTTS(feedback);
    } catch (e: any) {
        setIsLoading(false);
        addMessage(Sender.SYSTEM, `Review Error: ${e.message}`);
    }
  };

  const toggleVoiceMode = async () => {
    if (mode === InterviewMode.VOICE) {
        setMode(InterviewMode.TEXT);
        setIsLiveConnected(false);
        if (liveSessionRef.current) { liveSessionRef.current.disconnect(); liveSessionRef.current = null; }
        if (processorRef.current) { processorRef.current.disconnect(); processorRef.current = null; }
        if (sourceRef.current) { sourceRef.current.disconnect(); sourceRef.current = null; }
        if (mediaStreamRef.current) { mediaStreamRef.current.getTracks().forEach(track => track.stop()); mediaStreamRef.current = null; }
        stopAudioPlayback();
        if (audioContextRef.current) { await audioContextRef.current.close(); audioContextRef.current = null; }
    } else {
        try {
            setMode(InterviewMode.VOICE);
            currentTurnTextRef.current = "";
            const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
            const ctx = new AudioContextClass({ sampleRate: 24000 });
            audioContextRef.current = ctx;
            nextStartTimeRef.current = ctx.currentTime;

            const stream = await navigator.mediaDevices.getUserMedia({ audio: { channelCount: 1 } });
            mediaStreamRef.current = stream;

            const session = await connectToLiveSession({
                persona,
                onOpen: () => setIsLiveConnected(true),
                onAudioData: (base64) => {
                    if (!audioContextRef.current) return;
                    try {
                        const buffer = decodeAudioData(base64, audioContextRef.current, 24000);
                        const source = audioContextRef.current.createBufferSource();
                        source.buffer = buffer;
                        source.connect(audioContextRef.current.destination);
                        const now = audioContextRef.current.currentTime;
                        const startTime = Math.max(now, nextStartTimeRef.current);
                        source.start(startTime);
                        nextStartTimeRef.current = startTime + buffer.duration;
                        source.onended = () => { const idx = audioSourcesRef.current.indexOf(source); if (idx > -1) audioSourcesRef.current.splice(idx, 1); };
                        audioSourcesRef.current.push(source);
                    } catch (e) { console.error(e); }
                },
                onTranscript: (text, isUser, isFinal) => {
                    if (isUser) updateLastMessage(text, Sender.USER);
                    else {
                        currentTurnTextRef.current += text;
                        updateLastMessage(currentTurnTextRef.current, Sender.AI);
                        if (isFinal) currentTurnTextRef.current = "";
                    }
                },
                onInterrupted: () => {
                    stopAudioPlayback();
                    nextStartTimeRef.current = audioContextRef.current?.currentTime || 0;
                    currentTurnTextRef.current = "";
                },
                onClose: () => setIsLiveConnected(false),
                onError: (err) => { console.error(err); toggleVoiceMode(); }
            });

            liveSessionRef.current = session;
            const source = ctx.createMediaStreamSource(stream);
            sourceRef.current = source;
            const processor = ctx.createScriptProcessor(4096, 1, 1);
            processorRef.current = processor;
            processor.onaudioprocess = (e) => {
                if (!liveSessionRef.current) return;
                const inputData = e.inputBuffer.getChannelData(0);
                session.sendAudioChunk(downsampleBuffer(inputData, ctx.sampleRate, 16000));
            };
            source.connect(processor);
            processor.connect(ctx.destination);
        } catch (e) { setMode(InterviewMode.TEXT); }
    }
  };

  const extractTextFromPdf = async (file: File): Promise<string | null> => {
    try {
        const pdfjsLib = await import('pdfjs-dist');
        // Robust module loading (handle default or named export)
        const pdfjs = (pdfjsLib as any).default || pdfjsLib;

        if (!pdfjs.GlobalWorkerOptions.workerSrc) {
            // Use specific version to prevent mismatch errors
            const version = pdfjs.version || '3.11.174';
            pdfjs.GlobalWorkerOptions.workerSrc = `https://unpkg.com/pdfjs-dist@${version}/build/pdf.worker.min.js`;
        }

        const arrayBuffer = await file.arrayBuffer();
        const pdf = await pdfjs.getDocument({ data: arrayBuffer }).promise;

        let fullText = '';
        // Optimization: Limit to first 5 pages to prevent slow parsing of large docs
        const maxPages = Math.min(pdf.numPages, 5);

        for (let i = 1; i <= maxPages; i++) {
            const page = await pdf.getPage(i);
            const textContent = await page.getTextContent();
            const pageText = textContent.items.map((item: any) => item.str).join(' ');
            fullText += pageText + '\n';
        }

        if (pdf.numPages > 5) {
            fullText += "\n[Truncated remaining pages for performance]";
        }

        return fullText || null;
    } catch (e) {
        console.error("PDF Parse Error", e);
        return null; // Return null to signal failure
    }
  };

  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    try {
        let attachment: Attachment | null = null;
        if (file.type.startsWith('image/')) {
            const dataUrl = await new Promise<string>((resolve) => { const r = new FileReader(); r.onload = () => resolve(r.result as string); r.readAsDataURL(file); });
            attachment = { type: 'image', mimeType: file.type, data: dataUrl, fileName: file.name };
        } else if (file.type === 'application/pdf') {
            const text = await extractTextFromPdf(file);
            if (!text) {
                addMessage(Sender.SYSTEM, "Could not parse PDF. Please upload a plain text file or copy-paste content.");
                return;
            }
            attachment = { type: 'file', mimeType: 'text/plain', data: text, fileName: file.name };
            if (!resumeData && (text.includes("Experience") || text.includes("Education") || text.includes("Skills"))) {
                setResumeData({ data: text, mimeType: 'text/plain' });
                addMessage(Sender.SYSTEM, "Resume Context Loaded");
            }
        } else {
            const text = await new Promise<string>((resolve) => { const r = new FileReader(); r.onload = () => resolve(r.result as string); r.readAsText(file); });
            attachment = { type: 'file', mimeType: file.type, data: text, fileName: file.name };
            if (!resumeData && (text.includes("Experience") || text.includes("Education") || text.includes("Skills"))) {
                setResumeData({ data: text, mimeType: 'text/plain' });
                addMessage(Sender.SYSTEM, "Resume Context Loaded");
            }
        }

        if (attachment) {
            setPendingAttachment(attachment);
        }
    } catch (err: any) { 
        addMessage(Sender.SYSTEM, "Upload Failed"); 
    }
    finally { if (fileInputRef.current) fileInputRef.current.value = ''; }
  };

  return (
    <div className="h-[100dvh] bg-[#121212] text-[#E3E3E3] flex flex-col overflow-hidden font-sans">

      {/* 1. App Bar (Material Style) */}
      <header className="bg-[#1E1E1E] shadow-md px-4 py-3 flex items-center justify-between shrink-0 z-20 material-elevation-2 relative min-h-[64px]">
         {mode === InterviewMode.VOICE ? (
             <div className="flex items-center justify-between w-full animate-slide-up">
                <div className="flex items-center gap-3">
                     <div className="w-10 h-10 rounded-full bg-red-500/20 flex items-center justify-center animate-pulse">
                        <span className="material-symbols-rounded text-red-500 text-[24px]">mic</span>
                     </div>
                     <div className="flex flex-col">
                        <h1 className="text-[16px] font-bold tracking-tight text-white leading-tight">Live Interview</h1>
                        <span className="text-[10px] text-red-400 font-medium tracking-wide uppercase">{isLiveConnected ? 'Listening' : 'Connecting...'}</span>
                     </div>
                </div>

                <button 
                    onClick={toggleVoiceMode}
                    className="bg-red-600/10 hover:bg-red-600/20 text-red-500 border border-red-600/50 px-4 py-2 rounded-full text-xs font-bold flex items-center gap-2 transition-all active:scale-95"
                >
                    <span className="material-symbols-rounded text-[18px]">call_end</span>
                    <span>END</span>
                </button>
             </div>
         ) : (
             <>
                 <div className="flex items-center gap-3">
                     <div className="bg-gradient-to-br from-blue-500 to-purple-600 w-8 h-8 rounded-lg flex items-center justify-center shadow-lg">
                        <span className="material-symbols-rounded text-white text-[20px]">code_blocks</span>
                     </div>
                     <div>
                        <h1 className="text-[16px] font-bold tracking-tight text-white leading-tight">Nexus AI</h1>
                        <div className="flex items-center gap-1.5">
                           <span className="w-1.5 h-1.5 rounded-full bg-green-500"></span>
                           <span className="text-[10px] text-gray-400 font-medium">ONLINE</span>
                        </div>
                     </div>
                 </div>

                 <div className="flex items-center gap-2">
                    {resumeData && <span className="material-symbols-rounded text-green-400 text-[20px]" title="Resume Loaded">description</span>}

                    <button 
                        onClick={() => setPersona(persona === Persona.INTERVIEWER ? Persona.TUTOR : Persona.INTERVIEWER)}
                        className="bg-[#2C2C2C] text-[10px] font-bold px-3 py-1.5 rounded-full border border-[#3C3C3C] text-gray-300 active:bg-[#3C3C3C] transition-colors"
                    >
                        {persona} MODE
                    </button>
                 </div>
             </>
         )}
      </header>

      {/* 2. Body Area */}
      <div className="flex-1 relative overflow-hidden">

        {/* Chat Screen */}
        <div className={`absolute inset-0 flex flex-col transition-transform duration-300 ${activeTab === 'chat' ? 'translate-x-0' : '-translate-x-full'}`}>
           <div className={`flex-1 overflow-y-auto p-4 space-y-4 pb-24 bg-[#121212]`}>
                {messages.length === 0 && (
                    <div className="flex flex-col items-center justify-center h-full text-gray-600 gap-4 opacity-50">
                        <span className="material-symbols-rounded text-6xl">forum</span>
                        <p className="text-sm font-medium">Start your interview session</p>
                    </div>
                )}
                {messages.map((msg) => (
                    <TerminalMessage key={msg.id} message={msg} onPlayAudio={playTTS} />
                ))}
                {isLoading && (
                    <div className="flex justify-start px-2 py-2">
                        <div className="bg-[#2C2C2C] px-4 py-2 rounded-full rounded-tl-sm flex gap-1 items-center">
                            <div className="w-1.5 h-1.5 bg-gray-400 rounded-full typing-dot"></div>
                            <div className="w-1.5 h-1.5 bg-gray-400 rounded-full typing-dot"></div>
                            <div className="w-1.5 h-1.5 bg-gray-400 rounded-full typing-dot"></div>
                        </div>
                    </div>
                )}
                <div ref={messagesEndRef} className="h-4" />
           </div>
        </div>

        {/* Code Screen */}
        <div className={`absolute inset-0 bg-[#0d1117] transition-transform duration-300 ${activeTab === 'code' ? 'translate-x-0' : 'translate-x-full'}`}>
           <CodeEditor onReviewRequest={handleCodeReviewRequest} />
        </div>
      </div>

      {/* 3. Input Area (Always visible even in Voice Mode, allowing text/coding) */}
      <div className={`bg-[#1E1E1E] p-3 border-t border-[#2C2C2C] transition-transform duration-300 ${activeTab === 'chat' ? 'translate-y-0' : 'translate-y-full absolute bottom-0 w-full'}`}>
          {pendingAttachment && (
             <div className="mx-2 mb-2 p-2 bg-[#2C2C2C] rounded-lg flex items-center justify-between border border-[#3C3C3C]">
                 <div className="flex items-center gap-2 overflow-hidden">
                     <span className="material-symbols-rounded text-blue-400 text-sm">attachment</span>
                     <span className="text-xs text-gray-300 truncate">{pendingAttachment.fileName}</span>
                 </div>
                 <button onClick={() => setPendingAttachment(null)} className="text-gray-500 hover:text-red-400">
                     <span className="material-symbols-rounded text-sm">close</span>
                 </button>
             </div>
          )}

          <div className="flex items-center gap-2">
             <button onClick={() => fileInputRef.current?.click()} className="p-3 text-gray-400 hover:text-white rounded-full hover:bg-[#2C2C2C] transition-colors flex-shrink-0">
                 <span className="material-symbols-rounded">attach_file</span>
             </button>

             <button 
                onClick={stopAudioPlayback}
                className="p-3 text-red-400 hover:text-red-300 rounded-full hover:bg-[#2C2C2C] transition-colors flex-shrink-0"
                title="Stop Audio"
             >
                 <span className="material-symbols-rounded">stop_circle</span>
             </button>

             <input type="file" ref={fileInputRef} className="hidden" onChange={handleFileSelect} accept="image/*,.pdf,.txt,.js,.ts,.py" />

             <form onSubmit={(e) => handleTextSubmit(e)} className="flex-1 bg-[#2C2C2C] rounded-3xl border border-[#3C3C3C] focus-within:border-gray-500 transition-colors flex items-center px-4 py-2 min-h-[48px]">
                 <input 
                    type="text" 
                    value={inputValue}
                    onChange={(e) => setInputValue(e.target.value)}
                    placeholder="Message..."
                    className="bg-transparent border-none outline-none text-white w-full placeholder-gray-500 text-[15px]"
                    disabled={isLoading}
                 />
             </form>

             <button 
                onClick={(e) => inputValue.trim() ? handleTextSubmit(e, inputValue) : toggleVoiceMode()}
                className={`p-3 rounded-full shadow-lg transition-transform active:scale-95 flex items-center justify-center flex-shrink-0 ${inputValue.trim() ? 'bg-blue-600 text-white' : 'bg-[#2C2C2C] text-white border border-[#3C3C3C]'}`}
             >
                 <span className="material-symbols-rounded">
                    {inputValue.trim() ? 'send' : 'mic'}
                 </span>
             </button>
          </div>
      </div>

      {/* 4. Bottom Navigation Bar */}
      <nav className="bg-[#1E1E1E] border-t border-[#2C2C2C] pb-safe">
         <div className="flex justify-around items-center h-16">
             <button 
               onClick={() => setActiveTab('chat')} 
               className={`flex flex-col items-center gap-1 w-full h-full justify-center ${activeTab === 'chat' ? 'text-blue-400' : 'text-gray-500'}`}
             >
                <span className={`material-symbols-rounded transition-transform ${activeTab === 'chat' ? 'scale-110 fill-current' : ''}`}>chat_bubble</span>
                <span className="text-[10px] font-medium">Interview</span>
             </button>

             <button 
               onClick={() => setActiveTab('code')}
               className={`flex flex-col items-center gap-1 w-full h-full justify-center ${activeTab === 'code' ? 'text-blue-400' : 'text-gray-500'}`}
             >
                <span className={`material-symbols-rounded transition-transform ${activeTab === 'code' ? 'scale-110 fill-current' : ''}`}>terminal</span>
                <span className="text-[10px] font-medium">Workspace</span>
             </button>
         </div>
      </nav>
    </div>
  );
};

export default App;

import { defineConfig, loadEnv } from 'vite';
import react from '@vitejs/plugin-react';

export default defineConfig(({ mode }) => {
  const env = loadEnv(mode, (process as any).cwd(), '');
  const HF_TOKEN = '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';

  return {
    plugins: [react()],
    define: {
      // Define process.env as a single object to prevent conflicts
      'process.env': JSON.stringify({
        ...env,
        HF_TOKEN: HF_TOKEN,
        NODE_ENV: mode,
      }),
      'process.version': JSON.stringify('v16.0.0'),
      'global': 'window',
    },
    build: {
      target: 'esnext',
      minify: 'esbuild',
      rollupOptions: {
        output: {
          manualChunks: {
            'vendor': ['react', 'react-dom', 'uuid', 'openai', '@google/genai'],
            'pdfjs': ['pdfjs-dist'],
          },
        },
      },
      chunkSizeWarningLimit: 600,
    },
    optimizeDeps: {
      include: ['pdfjs-dist', '@google/genai'],
    },
  };
});

